'use client';

import { useState } from 'react';
import Link from 'next/link';
import { usePathname } from 'next/navigation';
import { signOut, useSession } from 'next-auth/react';
import { Icons } from '@/components/ui/icons';
import { cn } from '@/lib/utils';
import { Button } from '@/components/ui';

const _navigation = [
  { name: 'Dashboard', href: '/dashboard', icon: Icons.layoutDashboard },
  { name: 'Expenses', href: '/expenses', icon: Icons.receipt },
  { name: 'Goals', href: '/goals', icon: Icons.target },
  { name: 'Challenges', href: '/challenges', icon: Icons.trophy },
  { name: 'Settings', href: '/settings', icon: Icons.settings },
];

export default function DashboardLayout({ children }: { children: React.ReactNode }) {
  const _pathname = usePathname();
  const { data: session } = useSession();
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  return (
    <div className="min-h-screen bg-background">
      {/* Sidebar */}
      <aside
        className={cn(
          'fixed inset-y-0 left-0 z-50 w-64 transform bg-card transition-transform duration-200 ease-in-out',
          isSidebarOpen ? 'translate-x-0' : '-translate-x-full'
        )}
      >
        <div className="flex h-16 items-center justify-between px-4">
          <Link href="/dashboard" className="flex items-center space-x-2">
            <img src="/Full size.svg" alt="StackZen Logo" className="h-8 w-auto" />
            <span className="text-xl font-bold">StackZen</span>
          </Link>
          <Button
            variant="ghost"
            size="icon"
            onClick={() => setIsSidebarOpen(false)}
            className="lg:hidden"
          >
            <Icons.x className="h-5 w-5" />
          </Button>
        </div>

        <nav className="space-y-1 px-2 py-4">
          {_navigation.map(item => {
            const _isActive = _pathname === item.href;
            return (
              <Link
                key={item.name}
                href={item.href}
                className={cn(
                  'flex items-center space-x-2 rounded-lg px-3 py-2 text-sm font-medium transition-colors',
                  _isActive ? 'bg-primary text-primary-foreground' : 'hover:bg-muted'
                )}
              >
                <item.icon className="h-5 w-5" />
                <span>{item.name}</span>
              </Link>
            );
          })}
        </nav>

        <div className="absolute bottom-0 w-full border-t p-4">
          <div className="flex items-center space-x-4">
            <div className="flex-1">
              <p className="text-sm font-medium">{session?.user?.name}</p>
              <p className="text-xs text-muted-foreground">{session?.user?.email}</p>
            </div>
            <Button variant="ghost" size="icon" onClick={() => signOut({ callbackUrl: '/login' })}>
              <Icons.logout className="h-5 w-5" />
            </Button>
          </div>
        </div>
      </aside>

      {/* Main content */}
      <div
        className={cn(
          'flex min-h-screen flex-col transition-all duration-200 ease-in-out',
          isSidebarOpen ? 'lg:pl-64' : ''
        )}
      >
        {/* Header */}
        <header className="sticky top-0 z-40 border-b bg-background">
          <div className="flex h-16 items-center justify-between px-4">
            <Button
              variant="ghost"
              size="icon"
              onClick={() => setIsSidebarOpen(true)}
              className="lg:hidden"
            >
              <Icons.menu className="h-5 w-5" />
            </Button>
          </div>
        </header>

        {/* Page content */}
        <main className="flex-1 p-6">{children}</main>
      </div>
    </div>
  );
}

import { _MobileOptimizer } from '@/lib/mobile-optimization';
import { renderHook, act } from '@testing-library/react';

describe('MobileOptimizer', () => {
  let optimizer: MobileOptimizer;

  beforeEach(() => {
    optimizer = MobileOptimizer.getInstance();
    // Reset window dimensions
    Object.defineProperty(window, 'innerWidth', { value: 1024 });
    Object.defineProperty(window, 'innerHeight', { value: 768 });
  });

  it('should be a singleton', () => {
    const _instance1 = MobileOptimizer.getInstance();
    const _instance2 = MobileOptimizer.getInstance();
    expect(instance1).toBe(instance2);
  });

  it('should detect mobile device', () => {
    Object.defineProperty(window, 'innerWidth', { value: 375 });
    const { result } = renderHook(() => MobileOptimizer.useResponsive());
    expect(result.current.isMobile).toBe(true);
  });

  it('should detect tablet device', () => {
    Object.defineProperty(window, 'innerWidth', { value: 768 });
    const { result } = renderHook(() => MobileOptimizer.useResponsive());
    expect(result.current.isTablet).toBe(true);
  });

  it('should detect orientation changes', () => {
    Object.defineProperty(window, 'innerWidth', { value: 812 });
    Object.defineProperty(window, 'innerHeight', { value: 375 });
    const { result } = renderHook(() => MobileOptimizer.useResponsive());
    expect(result.current.orientation).toBe('landscape');

    act(() => {
      Object.defineProperty(window, 'innerWidth', { value: 375 });
      Object.defineProperty(window, 'innerHeight', { value: 812 });
      window.dispatchEvent(new Event('resize'));
    });

    expect(result.current.orientation).toBe('portrait');
  });

  it('should optimize touch events', () => {
    const _element = document.createElement('div');
    MobileOptimizer.optimizeTouchEvents(element);
    expect(element.style.touchAction).toBe('manipulation');
    expect(element.style.webkitTapHighlightColor).toBe('transparent');
  });

  it('should optimize scrolling', () => {
    const _element = document.createElement('div');
    MobileOptimizer.optimizeScrolling(element);
    expect(element.style.overscrollBehavior).toBe('contain');
    expect(element.style.webkitOverflowScrolling).toBe('touch');
  });

  it('should handle swipe gestures', () => {
    const _element = document.createElement('div');
    const _onSwipeLeft = jest.fn();
    const _onSwipeRight = jest.fn();

    MobileOptimizer.setupGestureHandling(element, {
      onSwipeLeft,
      onSwipeRight,
    });

    // Simulate swipe left
    const _touchStart = new TouchEvent('touchstart', {
      touches: [{ clientX: 100, clientY: 0 }],
    });
    const _touchEnd = new TouchEvent('touchend', {
      changedTouches: [{ clientX: 0, clientY: 0 }],
    });

    element.dispatchEvent(touchStart);
    element.dispatchEvent(touchEnd);

    expect(onSwipeLeft).toHaveBeenCalled();
    expect(onSwipeRight).not.toHaveBeenCalled();
  });

  it('should get mobile-specific styles', () => {
    Object.defineProperty(window, 'innerWidth', { value: 375 });
    const _styles = MobileOptimizer.getMobileStyles();
    expect(styles.fontSize).toBe('16px');
    expect(styles.padding).toBe('16px');
  });
});

'use client';
import { _useState } from 'react';
import { Button } from '@/components/ui';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { _motion } from 'framer-motion';

export default function ForgotPasswordPage() {
  const [email, setEmail] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);

  function validateEmail(email: string) {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  }

  async function onSubmit(e: React.FormEvent<HTMLFormElement>) {
    e.preventDefault();
    setError(null);
    setSuccess(null);
    if (!validateEmail(email)) {
      setError('Please enter a valid email address.');
      return;
    }
    setIsLoading(true);
    try {
      // Simulate API call
      await new Promise(resolve => setTimeout(resolve, 1200));
      setSuccess('If your email is registered, you&apos;ll receive a password reset link.');
    } catch {
      setError('Something went wrong. Please try again.');
    } finally {
      setIsLoading(false);
    }
  }

  return (
    <div className="mx-auto mt-12 w-full max-w-md rounded-2xl bg-white p-8 shadow-xl dark:bg-gray-800">
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.4 }}
        className="mb-8 text-center"
      >
        <h1 className="mb-2 bg-gradient-to-r from-emerald-600 to-emerald-400 bg-clip-text text-3xl font-bold text-transparent">
          Forgot your password?
        </h1>
        <p className="text-gray-600 dark:text-gray-400">
          Enter your email and we&apos;ll send you a reset link.
        </p>
      </motion.div>
      <motion.form
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 0.2 }}
        onSubmit={onSubmit}
        className="space-y-6"
      >
        <div>
          <Label htmlFor="email">Email</Label>
          <Input
            id="email"
            name="email"
            type="email"
            autoComplete="email"
            required
            value={email}
            onChange={e => setEmail(e.target.value)}
            disabled={isLoading}
            className="mt-2 h-12 text-base"
          />
        </div>
        {error && (
          <motion.p
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            className="text-sm text-red-500"
          >
            {error}
          </motion.p>
        )}
        {success && (
          <motion.p
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            className="text-sm text-emerald-600"
          >
            {success}
          </motion.p>
        )}
        <Button
          type="submit"
          className="h-12 w-full bg-gradient-to-r from-emerald-600 to-emerald-700 text-base font-semibold text-white shadow-lg transition-all duration-200 hover:from-emerald-700 hover:to-emerald-800 hover:shadow-xl"
          disabled={isLoading}
        >
          {isLoading ? 'Sending...' : 'Send Reset Link'}
        </Button>
      </motion.form>
      <div className="mt-8 text-center">
        <a
          href="/login"
          className="font-medium text-emerald-600 transition-colors duration-200 hover:text-emerald-500 dark:text-emerald-400"
        >
          Back to login
        </a>
      </div>
    </div>
  );
}

'use client';

import { useState, useRef, useEffect } from 'react';
import { useRouter, useSearchParams } from 'next/navigation';
import { Button } from '@/components/ui';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Icons } from '@/components/ui';
import { _Checkbox } from '@/components/ui/checkbox';
import { _signIn } from 'next-auth/react';

const PLAN_LABELS: Record<string, string> = {
  FREE: 'Starter (Free Trial)',
  PRO: 'Pro',
  LIFETIME: 'Zen Access (Lifetime)',
  ZEN_PLUS: 'Zen+ Coaching',
  COACHING_SESSION: '1-on-1 Coaching Session',
};
const PLAN_PRICES: Record<string, string> = {
  FREE: '$6.99/mo after trial',
  PRO: '$14.99/mo or $139/yr',
  LIFETIME: '$249 one-time',
  ZEN_PLUS: '$49/mo or $499/yr',
  COACHING_SESSION: '$65/session',
};
const PLAN_FEATURES: Record<string, string[]> = {
  FREE: ['Basic budgeting tools', 'Community access', '14-day free trial'],
  PRO: ['All Starter features', 'Advanced analytics', 'Priority support', 'Bank sync'],
  LIFETIME: ['All Pro features', 'Lifetime access', 'Exclusive webinars', 'Priority support'],
  ZEN_PLUS: [
    'Exclusive coaching for Pro/Zen users',
    'Monthly expert review',
    'Accountability plan',
    'Priority support',
    'Coaching portal access',
  ],
  COACHING_SESSION: [
    '45-minute Zoom call',
    'Post-session action plan',
    'Financial health audit',
    'Pay-as-you-go option',
  ],
};

export default function RegisterPage() {
  const _router = useRouter();
  const _searchParams = useSearchParams();
  const [isLoading, setIsLoading] = useState(false);
  const [agreeToTerms, setAgreeToTerms] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [emailError, setEmailError] = useState<string | null>(null);
  const [shake, setShake] = useState(false);
  const _formRef = useRef<HTMLFormElement>(null);

  // Plan/cycle state
  const [plan, setPlan] = useState<string>('FREE');
  const [cycle, setCycle] = useState<string>('monthly');
  const [country, setCountry] = useState<string>('');
  const [state, setState] = useState<string>('');

  useEffect(() => {
    const _planParam = searchParams.get('plan');
    const _cycleParam = searchParams.get('cycle');
    if (planParam && PLAN_LABELS[planParam.toUpperCase()]) {
      setPlan(planParam.toUpperCase());
    }
    if (cycleParam && ['monthly', 'annual'].includes(cycleParam.toLowerCase())) {
      setCycle(cycleParam.toLowerCase());
    }
  }, [searchParams]);

  function validateEmail(email: string) {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  }

  async function onSubmit(event: React.FormEvent<HTMLFormElement>) {
    event.preventDefault();
    setIsLoading(true);
    setError(null);
    setEmailError(null);

    const _formData = new FormData(event.currentTarget);
    const _name = formData.get('name') as string;
    const _email = formData.get('email') as string;
    const _password = formData.get('password') as string;
    const _confirmPassword = formData.get('confirmPassword') as string;

    if (!validateEmail(email)) {
      setEmailError('Please enter a valid email address.');
      setIsLoading(false);
      setShake(true);
      setTimeout(() => setShake(false), 500);
      return;
    }
    if (password !== confirmPassword) {
      setError('Passwords do not match');
      setIsLoading(false);
      setShake(true);
      setTimeout(() => setShake(false), 500);
      return;
    }
    if (password.length < 8) {
      setError(
        'Password is too weak. Use at least 8 characters, a number, an uppercase letter, and a symbol.'
      );
      setIsLoading(false);
      setShake(true);
      setTimeout(() => setShake(false), 500);
      return;
    }
    if (!agreeToTerms) {
      setError('You must agree to the Terms of Service and Privacy Policy.');
      setIsLoading(false);
      setShake(true);
      setTimeout(() => setShake(false), 500);
      return;
    }
    try {
      const _response = await fetch('/api/auth/signup', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          name,
          email,
          password,
          plan,
          cycle,
          country,
          state,
        }),
      });

      const _data = await response.json();

      if (!response.ok) {
        throw new Error(data.error || 'Something went wrong');
      }

      // If the response contains a URL, it's a Stripe Checkout session
      if (data.url) {
        router.push(data.url);
      } else {
        // Otherwise, it's a free plan, redirect to onboarding
        router.push('/onboarding');
      }

      router.refresh();
    } catch (error) {
      setError(error instanceof Error ? error.message : 'Something went wrong');
      setShake(true);
      setTimeout(() => setShake(false), 500);
    } finally {
      setIsLoading(false);
    }
  }

  return (
    <div className="flex min-h-screen w-full items-center justify-center bg-background">
      <div className="w-full max-w-md space-y-6 rounded-xl border bg-white p-8 shadow-lg dark:bg-gray-900">
        {/* Google Signup Button */}
        <button
          type="button"
          onClick={() => signIn('google', { callbackUrl: '/dashboard' })}
          className="mb-6 flex w-full items-center justify-center gap-2 rounded-md border border-gray-300 bg-white px-4 py-2 text-neutral-900 hover:bg-gray-100 focus-visible:ring-2 focus-visible:ring-primary dark:bg-neutral-100 dark:text-neutral-900 dark:hover:bg-white"
        >
          <Icons.google className="mr-2 h-4 w-4" />
          Sign up with Google
        </button>
        <form
          ref={_formRef}
          onSubmit={onSubmit}
          className={`${shake ? 'animate-shake' : ''} space-y-6`}
          autoComplete="off"
        >
          {/* Plan summary card */}
          <div className="mb-4 flex flex-col gap-2 rounded-lg border bg-gray-100 p-4 dark:bg-gray-800">
            <div className="flex items-center justify-between">
              <div>
                <span className="font-semibold">Selected Plan:</span> {PLAN_LABELS[plan]}
              </div>
              <a href="/pricing" className="text-sm text-blue-600 underline">
                Change plan
              </a>
            </div>
            <div className="text-lg font-bold">{PLAN_PRICES[plan]}</div>
            <ul className="ml-5 list-disc text-sm">
              {PLAN_FEATURES[plan].map(f => (
                <li key={f}>{f}</li>
              ))}
            </ul>
            {plan === 'PRO' && (
              <div className="mt-2 flex gap-2">
                <Button
                  type="button"
                  variant={cycle === 'monthly' ? 'default' : 'outline'}
                  size="sm"
                  onClick={() => setCycle('monthly')}
                >
                  Monthly
                </Button>
                <Button
                  type="button"
                  variant={cycle === 'annual' ? 'default' : 'outline'}
                  size="sm"
                  onClick={() => setCycle('annual')}
                >
                  Annual
                </Button>
              </div>
            )}
            {plan === 'ZEN_PLUS' && (
              <div className="mt-2 flex gap-2">
                <Button
                  type="button"
                  variant={cycle === 'monthly' ? 'default' : 'outline'}
                  size="sm"
                  onClick={() => setCycle('monthly')}
                >
                  Monthly
                </Button>
                <Button
                  type="button"
                  variant={cycle === 'annual' ? 'default' : 'outline'}
                  size="sm"
                  onClick={() => setCycle('annual')}
                >
                  Annual
                </Button>
              </div>
            )}
          </div>
          <h2 className="mb-4 text-center text-2xl font-bold">Create your StackZen account</h2>
          <div>
            <Label htmlFor="name">Name</Label>
            <Input
              id="name"
              name="name"
              type="text"
              required
              disabled={isLoading}
              className="mt-2"
              autoComplete="name"
            />
          </div>
          <div>
            <Label htmlFor="email">Email</Label>
            <Input
              id="email"
              name="email"
              type="email"
              required
              disabled={isLoading}
              className="mt-2"
              autoComplete="email"
            />
            {emailError && <p className="mt-1 text-sm text-red-500">{emailError}</p>}
          </div>
          <div>
            <Label htmlFor="country">Country</Label>
            <Input
              id="country"
              name="country"
              type="text"
              required
              disabled={isLoading}
              className="mt-2"
              autoComplete="country"
              value={country}
              onChange={e => setCountry(e.target.value)}
            />
          </div>
          <div>
            <Label htmlFor="state">State/Province</Label>
            <Input
              id="state"
              name="state"
              type="text"
              disabled={isLoading}
              className="mt-2"
              autoComplete="address-level1"
              value={state}
              onChange={e => setState(e.target.value)}
            />
          </div>
          <div>
            <Label htmlFor="password">Password</Label>
            <Input
              id="password"
              name="password"
              type="password"
              required
              disabled={isLoading}
              className="mt-2"
              autoComplete="new-password"
            />
          </div>
          <div>
            <Label htmlFor="confirmPassword">Confirm Password</Label>
            <Input
              id="confirmPassword"
              name="confirmPassword"
              type="password"
              required
              disabled={isLoading}
              className="mt-2"
              autoComplete="new-password"
            />
          </div>
          <div className="flex items-center gap-2">
            <Checkbox
              id="terms"
              checked={agreeToTerms}
              onCheckedChange={v => setAgreeToTerms(!!v)}
              disabled={isLoading}
            />
            <Label htmlFor="terms" className="text-sm">
              I agree to the{' '}
              <a href="/terms" className="underline">
                Terms of Service
              </a>{' '}
              and{' '}
              <a href="/privacy" className="underline">
                Privacy Policy
              </a>
            </Label>
          </div>
          {error && <div className="text-center text-sm text-red-500">{error}</div>}
          <Button type="submit" className="w-full" disabled={isLoading}>
            {isLoading ? 'Creating account...' : 'Create Account'}
          </Button>
        </form>
      </div>
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { useRouter, useSearchParams } from 'next/navigation';
import { _createClient } from '@/lib/supabase/client';
import { Button } from '@/components/ui';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import {
  Card,
  CardContent,
  CardDescription,
  CardFooter,
  CardHeader,
  CardTitle,
} from '@/components/ui/card';
import { Icons } from '@/components/ui/icons';
import { _toast } from 'sonner';
import { Alert, AlertDescription } from '@/components/ui/alert';
import Progress from '@/components/ui/progress';
import { validatePassword, type PasswordStrength } from '@/lib/auth/password';

type AuthError = {
  message: string;
  status?: number;
};

export default function ResetPasswordPage() {
  const _router = useRouter();
  const _searchParams = useSearchParams();
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<AuthError | null>(null);
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [passwordStrength, setPasswordStrength] = useState<PasswordStrength | null>(null);
  const _supabase = createClient();

  useEffect(() => {
    const _token = searchParams.get('token');
    if (!token) {
      setError({
        message: 'Invalid or missing reset token. Please request a new password reset.',
      });
    }
  }, [searchParams]);

  useEffect(() => {
    if (password) {
      setPasswordStrength(validatePassword(password));
    } else {
      setPasswordStrength(null);
    }
  }, [password]);

  const _handleResetPassword = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError(null);

    try {
      if (password !== confirmPassword) {
        throw new Error('Passwords do not match');
      }

      if (!passwordStrength?.isValid) {
        throw new Error('Password does not meet the requirements');
      }

      const { error } = await supabase.auth.updateUser({
        password: password,
      });

      if (error) throw error;

      toast.success('Password has been reset successfully');
      router.push('/login');
    } catch (error: any) {
      console.error('Error resetting password:', error);
      setError({
        message: error.message || 'Error resetting password',
        status: error.status,
      });
      toast.error(error.message || 'Error resetting password');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="container flex h-screen w-screen flex-col items-center justify-center">
      <Card className="w-[350px]">
        <CardHeader>
          <CardTitle>Reset Password</CardTitle>
          <CardDescription>Enter your new password below</CardDescription>
        </CardHeader>
        <CardContent>
          {error && (
            <Alert variant="destructive" className="mb-4">
              <AlertDescription>{error.message}</AlertDescription>
            </Alert>
          )}
          <form onSubmit={handleResetPassword}>
            <div className="grid gap-4">
              <div className="grid gap-2">
                <Label htmlFor="password">New Password</Label>
                <Input
                  id="password"
                  type="password"
                  value={password}
                  onChange={e => setPassword(e.target.value)}
                  required
                  disabled={isLoading}
                />
                {passwordStrength && (
                  <div className="space-y-2">
                    <Progress value={(passwordStrength.score / 7) * 100} className="h-2" />
                    <div className="text-xs text-muted-foreground">
                      {passwordStrength.feedback.map((msg, i) => (
                        <p key={i} className="text-red-500">
                          • {msg}
                        </p>
                      ))}
                    </div>
                  </div>
                )}
              </div>
              <div className="grid gap-2">
                <Label htmlFor="confirmPassword">Confirm Password</Label>
                <Input
                  id="confirmPassword"
                  type="password"
                  value={confirmPassword}
                  onChange={e => setConfirmPassword(e.target.value)}
                  required
                  disabled={isLoading}
                />
              </div>
              <Button type="submit" disabled={isLoading || !passwordStrength?.isValid}>
