  const _filteredGoals = goals.filter(goal => {
    const _matchesSearch = goal.title.toLowerCase().includes(searchQuery.toLowerCase());
    const _matchesCategory = selectedCategory === 'all' || goal.category === selectedCategory;
    return matchesSearch && matchesCategory;
  });

  const _handleAddGoal = (data: any) => {
    const _newGoal = {
      id: Math.random().toString(36).substr(2, 9),
      title: data.title,
      targetAmount: parseFloat(data.targetAmount),
      currentAmount: parseFloat(data.currentAmount),
      deadline: data.deadline,
      category: data.category,
    };
    setGoals([...goals, newGoal]);
  };

  const _handleEditGoal = (id: string, data: any) => {
    setGoals(
      goals.map(goal =>
        goal.id === id
          ? {
              ...goal,
              title: data.title,
              targetAmount: parseFloat(data.targetAmount),
              currentAmount: parseFloat(data.currentAmount),
              deadline: data.deadline,
              category: data.category,
