interface GigFiltersProps {
  onFilterChange: (filters: {
    search: string;
    sortBy: 'newest' | 'oldest' | 'title';
    source: string | 'all';
  }) => void;
  sources: string[];
}

export function GigFilters({ onFilterChange, sources }: GigFiltersProps) {
  const [search, setSearch] = useState('');
  const [sortBy, setSortBy] = useState<'newest' | 'oldest' | 'title'>('newest');
  const [source, setSource] = useState<string>('all');

  const _handleSearch = (value: string) => {
    setSearch(value);
    onFilterChange({ search: value, sortBy, source });
  };

  const _handleSort = (value: 'newest' | 'oldest' | 'title') => {
    setSortBy(value);
    onFilterChange({ search, sortBy: value, source });
  };

  const _handleSourceChange = (value: string) => {
    setSource(value);
    onFilterChange({ search, sortBy, source: value });
  };

  return (
    <div className="mb-6 flex flex-col gap-4 sm:flex-row">
      <div className="relative flex-1">
        <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 transform text-muted-foreground" />
        <Input
          placeholder="Search gigs..."
          value={search}
          onChange={e => handleSearch(e.target.value)}
          className="pl-9"
        />
      </div>

      <Select value={sortBy} onValueChange={handleSort}>
        <SelectTrigger className="w-[180px]">
          <SelectValue placeholder="Sort by" />
        </SelectTrigger>
        <SelectContent>
          <SelectItem value="newest">Newest First</SelectItem>
          <SelectItem value="oldest">Oldest First</SelectItem>
          <SelectItem value="title">Title A-Z</SelectItem>
        </SelectContent>
      </Select>

      <Select value={source} onValueChange={handleSourceChange}>
        <SelectTrigger className="w-[180px]">
          <SelectValue placeholder="Filter by source" />
        </SelectTrigger>
        <SelectContent>
          <SelectItem value="all">All Sources</SelectItem>
          {sources.map(src => (
            <SelectItem key={src} value={src}>
              {src}
            </SelectItem>
          ))}
        </SelectContent>
      </Select>
    </div>
  );
}

'use client';

import { _useState } from 'react';
import { _Card } from '@/components/ui/card';
import { Badge } from '@/components/ui';
import { _GigFilters } from './GigFilters.tsx';
import { _AggregatedGig } from '@/lib/aggregation/gig-sources';

interface GigsClientProps {
  initialGigs: AggregatedGig[];
  category: string;
}

export function GigsClient({ initialGigs, category }: GigsClientProps) {
  // Filter gigs by category prop
  const _filteredByCategory = initialGigs.filter(gig => gig.category === category);
  const [gigs, setGigs] = useState(filteredByCategory);
  const _sources = Array.from(new Set(filteredByCategory.map(gig => gig.source)));

  const _handleFilterChange = (filters: {
    search: string;
    sortBy: 'newest' | 'oldest' | 'title';
    source: string | 'all';
  }) => {
    let filtered = [...filteredByCategory];

    // Apply search filter
    if (filters.search) {
      const _searchLower = filters.search.toLowerCase();
      filtered = filtered.filter(
        gig =>
          gig.title.toLowerCase().includes(searchLower) ||
          gig.description.toLowerCase().includes(searchLower)
      );
    }

    // Apply source filter
    if (filters.source !== 'all') {
      filtered = filtered.filter(gig => gig.source === filters.source);
    }

    // Apply sorting
    filtered.sort((a, b) => {
      switch (filters.sortBy) {
        case 'newest':
          return new Date(b.postedAt || '').getTime() - new Date(a.postedAt || '').getTime();
        case 'oldest':
          return new Date(a.postedAt || '').getTime() - new Date(b.postedAt || '').getTime();
        case 'title':
          return a.title.localeCompare(b.title);
        default:
          return 0;
      }
    });

    setGigs(filtered);
  };

  if (gigs.length === 0) {
    return (
      <div className="py-8 text-center text-muted-foreground">
        No gigs available in this category at the moment.
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <GigFilters sources={sources} onFilterChange={handleFilterChange} />

      <div className="grid grid-cols-1 gap-4 md:grid-cols-2 lg:grid-cols-3">
        {gigs.map(gig => (
          <Card key={gig.id} className="p-4 transition-shadow hover:shadow-lg">
            <h3 className="mb-2 text-lg font-semibold">{gig.title}</h3>
            <p className="mb-4 line-clamp-3 text-sm text-muted-foreground">{gig.description}</p>
            <div className="flex items-center justify-between">
              <Badge variant="secondary">{gig.source}</Badge>
              <a
                href={gig.url}
                target="_blank"
                rel="noopener noreferrer"
                className="text-sm text-primary hover:underline"
              >
                View Details →
              </a>
            </div>
          </Card>
        ))}
      </div>
    </div>
  );
}

