export default function InvoiceDetailPage() {
  const _router = useRouter();
  const _params = useParams();
  const _searchParams = useSearchParams();
  const _invoiceId = params?.id as string;
  const { toast } = useToast();

  // Handle payment success/error messages
  useEffect(() => {
    const _success = searchParams.get('success');
    const _canceled = searchParams.get('canceled');

    if (success === 'true') {
      toast({
        title: 'Payment Successful',
        description: 'Your invoice has been marked as paid.',
        variant: 'default',
      });
    } else if (canceled === 'true') {
      toast({
