    isLoading,
    error,
  } = useQuery<Invoice>({
    queryKey: ['invoice', invoiceId],
    queryFn: async () => {
      const _response = await fetch(`/api/invoices/${invoiceId}`);
      if (!response.ok) {
        throw new Error('Failed to fetch invoice');
      }
      return response.json();
    },
    enabled: !!invoiceId,
  });

  const _handlePayNow = async () => {
    try {
      const _response = await fetch(`/api/invoices/${invoiceId}/pay`, {
