const profileSchema = z.object({
  name: z.string().min(2, 'Name must be at least 2 characters'),
  email: z.string().email('Invalid email address'),
});

const passwordSchema = z
  .object({
    currentPassword: z.string().min(8, 'Password must be at least 8 characters'),
    newPassword: z.string().min(8, 'Password must be at least 8 characters'),
    confirmPassword: z.string(),
  })
  .refine(data => data.newPassword === data.confirmPassword, {
    message: "Passwords don't match",
    path: ['confirmPassword'],
  });

function SmartSavingControls() {
  const [rules, setRules] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchRules();
  }, []);

  const fetchRules = async () => {
    setLoading(true);
    try {
      const response = await fetch('/api/smart-saving/rules');
      if (response.ok) {
        const data = await response.json();
        setRules(data);
      }
    } finally {
      setLoading(false);
    }
  };

  const handleToggle = async (type: string, enabled: boolean) => {
    const rule = rules.find(r => r.type === type);
    const config = { ...rule?.config, enabled };
    await fetch('/api/smart-saving/rules', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        name: rule?.name || type,
        type,
        config,
      }),
    });
    fetchRules();
  };

  if (loading) {
    return <div className="p-4">Loading smart saving controls...</div>;
  }

  return (
    <Card className="mb-6">
      <CardHeader>
        <CardTitle>Smart Saving Controls</CardTitle>
      </CardHeader>
      <CardContent>
        <div className="space-y-4">
          {['roundup', 'auto', 'budget', 'trigger', 'income_split'].map(type => {
            const rule = rules.find(r => r.type === type);
            return (
              <div key={type} className="flex items-center justify-between">
                <span className="capitalize">{type.replace('_', ' ')} rule</span>
                <Switch
                  checked={!!rule?.config?.enabled}
                  onCheckedChange={checked => handleToggle(type, checked)}
                />
              </div>
            );
          })}
        </div>
      </CardContent>
    </Card>
  );
}

export default function SettingsPage() {
  const { theme, setTheme } = useTheme();
  const [isLoading, setIsLoading] = useState(false);
  const [settings, setSettings] = useState({
    theme: 'system',
    currency: 'USD',
    emailNotifications: true,
    pushNotifications: true,
    weeklyReports: true,
    goalReminders: true,
    challengeUpdates: true,
  });
  const [showPasswordDialog, setShowPasswordDialog] = useState(false);
  const [showEmailDialog, setShowEmailDialog] = useState(false);
  const [pendingEmail, setPendingEmail] = useState('');
  const { data: session } = useSession();

  const profileForm = useForm({
    resolver: zodResolver(profileSchema),
    defaultValues: {
      name: '',
      email: '',
    },
  });

  const passwordForm = useForm({
    resolver: zodResolver(passwordSchema),
    defaultValues: {
      currentPassword: '',
      newPassword: '',
      confirmPassword: '',
    },
  });

  const currencyOptions = getCurrencyOptions();

  useEffect(() => {
    const fetchSettings = async () => {
      try {
        const response = await fetch('/api/settings');
        if (response.ok) {
          const data = await response.json();
          if (data) {
            setSettings(data);
            if (data.theme) {
              setTheme(data.theme);
            }
          }
        }
      } catch (error) {
        console.error('Failed to fetch settings:', error);
        toast.error('Failed to load settings');
      }
    };

    fetchSettings();
  }, [setTheme]);

  const handleNotificationChange = async (key: keyof typeof settings) => {
    try {
      const newSettings = {
        ...settings,
        [key]: !settings[key],
      };

      const response = await fetch('/api/settings', {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(newSettings),
      });

      if (response.ok) {
        setSettings(newSettings);
        toast.success('Settings updated successfully');
      } else {
        throw new Error('Failed to update settings');
      }
    } catch (error) {
      console.error('Failed to update settings:', error);
      toast.error('Failed to update settings');
    }
  };

  const handleThemeChange = async (newTheme: string) => {
    try {
      const newSettings = {
        ...settings,
        theme: newTheme,
      };

      const response = await fetch('/api/settings', {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(newSettings),
      });

      if (response.ok) {
        setSettings(newSettings);
        setTheme(newTheme);
        toast.success('Theme updated successfully');
      } else {
        throw new Error('Failed to update theme');
      }
    } catch (error) {
      console.error('Failed to update theme:', error);
      toast.error('Failed to update theme');
    }
