        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(options),
      });

      if (!response.ok) {
        throw new Error('Export failed');
      }

      const data = await response.json();
      return data;
    } catch (error) {
      console.error('Export failed:', error);
      toast.error('Failed to export data');
      return [];
    }
