export async function GET(request: Request) {
  try {
    const _session = await getServerSession();
    if (!session?.user) {
      return new NextResponse('Unauthorized', { status: 401 });
    }

    // Check if user is super admin only
    const _user = await prisma.user.findUnique({
      where: { email: session.user.email! },
      select: { role: true },
    });

    if (user?.role !== 'SUPER_ADMIN') {
      return new NextResponse('Forbidden', { status: 403 });
    }

    const [databaseHealth, redisHealth, apiHealth, systemMetrics] = await Promise.all([
      checkDatabaseHealth(),
      checkRedisHealth(),
      checkAPIEndpoints(),
      getSystemMetrics(),
    ]);

    // API latency stats
    let apiLatencyStats = { avg: 0, min: 0, max: 0 };
    if (Array.isArray(apiHealth)) {
      const _latencies = apiHealth
        .map((ep: any) => ep.latency)
        .filter((l: any) => typeof l === 'number');
      if (latencies.length) {
        apiLatencyStats = {
          avg: Math.round(latencies.reduce((a, b) => a + b, 0) / latencies.length),
          min: Math.min(...latencies),
          max: Math.max(...latencies),
        };
      }
    }

    return NextResponse.json({
      timestamp: new Date().toISOString(),
      services: {
        database: databaseHealth,
        redis: redisHealth,
        api: apiHealth,
      },
      metrics: systemMetrics,
      apiLatencyStats,
    });
  } catch (error) {
    console.error('Error checking system health:', error);
    // In development, return error details for debugging
    if (process.env.NODE_ENV === 'development') {
      return NextResponse.json({ error: error.message, stack: error.stack }, { status: 500 });
    }
    return new NextResponse('Internal Server Error', { status: 500 });
  }
}

