import { _headers } from 'next/headers';
import { _NextResponse } from 'next/server';
import Stripe from 'stripe';
import { _logger } from '@/lib/monitoring';
import { _prisma } from '@/lib/prisma';
import { _db } from '@/lib/db';

const _stripe = new Stripe(process.env.STRIPE_SECRET_KEY!, {
  apiVersion: '2023-10-16',
});

const _webhookSecret = process.env.STRIPE_WEBHOOK_SECRET!;

export async function POST(req: Request) {
  try {
    const _body = await req.text();
    const _signature = headers().get('stripe-signature')!;

    let event: Stripe.Event;

    try {
      event = stripe.webhooks.constructEvent(body, signature, webhookSecret);
    } catch (err) {
      console.error('Webhook signature verification failed:', err);
      return new NextResponse('Webhook signature verification failed', { status: 400 });
    }

    switch (event.type) {
      case 'checkout.session.completed': {
        const _session = event.data.object as Stripe.Checkout.Session;
        const { invoiceId } = session.metadata!;

        // Update invoice status
        await prisma.invoice.update({
          where: { id: invoiceId },
          data: {
            status: 'paid',
            paidAt: new Date(),
            stripePaymentIntent: session.payment_intent as string,
          },
        });

        break;
      }

      case 'payment_intent.succeeded': {
        const _paymentIntent = event.data.object as Stripe.PaymentIntent;
        const _invoiceId = paymentIntent.metadata.invoiceId;

        if (invoiceId) {
          await prisma.invoice.update({
            where: { id: invoiceId },
            data: {
              status: 'paid',
              paidAt: new Date(),
              stripePaymentIntent: paymentIntent.id,
            },
          });
        }

        break;
      }

      case 'payment_intent.payment_failed': {
        const _paymentIntent = event.data.object as Stripe.PaymentIntent;
        const _invoiceId = paymentIntent.metadata.invoiceId;

        if (invoiceId) {
          await prisma.invoice.update({
            where: { id: invoiceId },
            data: {
              status: 'overdue',
            },
          });
        }

        break;
      }
    }

    return new NextResponse(null, { status: 200 });
  } catch (error) {
    console.error('Error processing webhook:', error);
    return new NextResponse('Internal Server Error', { status: 500 });
  }
}

