export default function StripeConnectRefresh() {
  const _router = useRouter();
  const { toast } = useToast();
  const [isRetrying, setIsRetrying] = useState(false);

  const _handleRetry = async () => {
    try {
      setIsRetrying(true);
      const _response = await fetch('/api/stripe/connect');
      if (!response.ok) {
        throw new Error('Failed to create new onboarding link');
      }

      const { url } = await response.json();
      window.location.href = url;
    } catch (error) {
      toast({
        title: 'Error',
        description: error instanceof Error ? error.message : 'Failed to retry Stripe connection',
        variant: 'destructive',
      });
    } finally {
      setIsRetrying(false);
    }
  };

  return (
    <div className="container max-w-2xl py-12">
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2 text-destructive">
