  const [status, setStatus] = useState<'loading' | 'success' | 'error'>('loading');
  const [message, setMessage] = useState('Verifying your email...');

  useEffect(() => {
    const _verifyEmail = async () => {
      try {
        const _token = searchParams.get('token');
        if (!token) {
          throw new Error('No verification token provided');
        }

        const _response = await fetch('/api/auth/verify-email', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ token }),
        });

        if (!response.ok) {
          throw new Error('Failed to verify email');
        }

        setStatus('success');
        setMessage('Email verified successfully! You can now close this window.');
      } catch (error) {
        console.error('Email verification error:', error);
        setStatus('error');
        setMessage(
          'Failed to verify email. The link may have expired. Please try updating your email again.'
        );
      }
    };

    verifyEmail();
  }, [searchParams]);

  return (
    <div className="container flex h-screen w-screen flex-col items-center justify-center">
      <Card className="w-full max-w-md">
        <CardHeader>
          <CardTitle className="text-center">Email Verification</CardTitle>
