interface WellnessData {
  latestScore: WellnessScore;
  goals: CategoryGoal[];
}

export default function WellnessPage() {
  const { toast } = useToast();
  const _queryClient = useQueryClient();
  const [showGoalForm, setShowGoalForm] = useState(false);
  const [dismissedGoals, setDismissedGoals] = useState<Set<string>>(new Set());

  // Fetch wellness data
  const { data: wellnessData, isLoading: isLoadingWellness } = useQuery<WellnessData>({
    queryKey: ['wellness'],
    queryFn: async () => {
      const _response = await fetch('/api/wellness');
      if (!response.ok) throw new Error('Failed to fetch wellness data');
      return response.json();
    },
  });

  // Fetch historical scores
  const { data: scores, isLoading: isLoadingScores } = useQuery<WellnessScore[]>({
    queryKey: ['wellness-scores'],
    queryFn: async () => {
      const _response = await fetch('/api/wellness/scores');
      if (!response.ok) throw new Error('Failed to fetch wellness scores');
      return response.json();
    },
  });

  const _handleAddGoal = async (goal: Omit<CategoryGoal, 'id'>) => {
    try {
      const _response = await fetch('/api/wellness/goals', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(goal),
      });

      if (!response.ok) throw new Error('Failed to add goal');

      await queryClient.invalidateQueries({ queryKey: ['wellness'] });
      toast({
        title: 'Goal Added',
        description: 'Your new financial goal has been created successfully.',
      });
    } catch (error) {
      toast({
        title: 'Error',
        description: 'Failed to add goal. Please try again.',
        variant: 'destructive',
      });
    }
  };

  const _handleUpdateGoal = async (goal: CategoryGoal) => {
    try {
      const _response = await fetch(`/api/wellness/goals/${goal.id}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(goal),
      });

      if (!response.ok) throw new Error('Failed to update goal');

      await queryClient.invalidateQueries({ queryKey: ['wellness'] });
      toast({
        title: 'Goal Updated',
        description: 'Your financial goal has been updated successfully.',
      });
    } catch (error) {
      toast({
        title: 'Error',
        description: 'Failed to update goal. Please try again.',
        variant: 'destructive',
      });
    }
  };

  const _handleDeleteGoal = async (goalId: string) => {
    try {
      const _response = await fetch(`/api/wellness/goals/${goalId}`, {
        method: 'DELETE',
      });

      if (!response.ok) throw new Error('Failed to delete goal');

      await queryClient.invalidateQueries({ queryKey: ['wellness'] });
      toast({
        title: 'Goal Deleted',
        description: 'Your financial goal has been removed successfully.',
      });
    } catch (error) {
      toast({
        title: 'Error',
        description: 'Failed to delete goal. Please try again.',
        variant: 'destructive',
      });
    }
  };

  const _handleDismissNotification = (goalId: string) => {
    setDismissedGoals(prev => new Set([...prev, goalId]));
  };

  if (isLoadingWellness || isLoadingScores) {
    return (
      <div className="flex min-h-screen items-center justify-center">
        <div className="h-12 w-12 animate-spin rounded-full border-b-2 border-primary"></div>
      </div>
    );
  }

  if (!wellnessData || !scores) {
    return (
      <div className="flex min-h-screen items-center justify-center">
        <Card className="p-6 text-center">
          <h2 className="mb-2 text-xl font-semibold">No Data Available</h2>
          <p className="text-muted-foreground">
            Please complete your financial assessment to view your wellness dashboard.
          </p>
        </Card>
      </div>
    );
  }

  // Filter out dismissed goals
  const _activeGoals = wellnessData.goals.filter(goal => !dismissedGoals.has(goal.id));

  return (
    <div className="container mx-auto max-w-7xl px-4 py-8">
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        className="space-y-8"
      >
        {/* Header */}
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-3xl font-bold">Financial Wellness</h1>
            <p className="mt-1 text-muted-foreground">Track your financial health and progress</p>
          </div>
          <Button onClick={() => setShowGoalForm(true)} className="bg-primary hover:bg-primary/90">
            Add New Goal
          </Button>
        </div>

        {/* Notifications */}
        <GoalNotifications goals={activeGoals} onDismiss={handleDismissNotification} />

        {/* Main Grid */}
        <div className="grid grid-cols-1 gap-8 lg:grid-cols-2">
          {/* Left Column */}
          <div className="space-y-8">
            <WellnessScorecard score={wellnessData.latestScore} />
            <CategoryTrends scores={scores} />
          </div>

          {/* Right Column */}
          <div className="space-y-8">
            <CategoryGoals
              scores={scores}
              goals={activeGoals}
              onAddGoal={handleAddGoal}
              onUpdateGoal={handleUpdateGoal}
              onDeleteGoal={handleDeleteGoal}
            />

            {/* Recommendations Section */}
            {wellnessData.latestScore.recommendations.length > 0 && (
              <Card className="p-6">
                <h3 className="mb-4 text-lg font-semibold">Recommendations</h3>
                <div className="space-y-4">
                  {wellnessData.latestScore.recommendations.map((rec, index) => (
                    <motion.div
                      key={index}
                      initial={{ opacity: 0, x: -20 }}
                      animate={{ opacity: 1, x: 0 }}
                      transition={{ delay: index * 0.1 }}
                      className="flex items-start space-x-3"
                    >
                      <div
                        className={`mt-2 h-2 w-2 rounded-full ${
                          rec.priority === 'high'
                            ? 'bg-red-500'
                            : rec.priority === 'medium'
                              ? 'bg-yellow-500'
                              : 'bg-green-500'
                        }`}
                      />
                      <div>
                        <p className="font-medium">{rec.title}</p>
                        <p className="text-sm text-muted-foreground">{rec.description}</p>
                      </div>
                    </motion.div>
                  ))}
                </div>
              </Card>
            )}
          </div>
        </div>
      </motion.div>
    </div>
  );
}

