interface OnboardingData {
  // Income Data
  monthlyIncome: number;
  incomeSources: Array<{
    name: string;
    amount: number;
    frequency: 'monthly' | 'weekly' | 'biweekly' | 'annually';
  }>;
  incomeStability: number; // months

  // Debt Data
  totalDebt: number;
  monthlyDebtPayments: number;
  debtTypes: Array<{
    name: string;
    amount: number;
    monthlyPayment: number;
    interestRate: number;
  }>;

  // Savings Data
  totalSavings: number;
  monthlySavingsGoal: number;
  emergencyFundMonths: number;

  // Goals
  financialGoals: Array<{
    name: string;
    target: number;
    deadline: string;
    category: string;
  }>;

  // Personal Data
  riskTolerance: 'conservative' | 'moderate' | 'aggressive';
  financialLiteracy: 'beginner' | 'intermediate' | 'advanced';
  lifeStage: 'student' | 'early_career' | 'mid_career' | 'late_career' | 'retirement';
  familySize: number;
  location: string;

  // Investment Preferences
  investmentExperience: 'none' | 'beginner' | 'intermediate' | 'advanced';
  preferredInvestmentTypes: string[];
}

