  const [step, setStep] = useState(0);
  const [data, setData] = useState<OnboardingData>({
    monthlyIncome: 0,
    incomeSources: [{ name: '', amount: 0, frequency: 'monthly' }],
    incomeStability: 12,
    totalDebt: 0,
    monthlyDebtPayments: 0,
    debtTypes: [],
    totalSavings: 0,
    monthlySavingsGoal: 0,
    emergencyFundMonths: 3,
    financialGoals: [],
    riskTolerance: 'moderate',
    financialLiteracy: 'beginner',
    lifeStage: 'early_career',
    familySize: 1,
    location: '',
    investmentExperience: 'none',
    preferredInvestmentTypes: [],
  });

  const _router = useRouter();

  const _steps = ['income', 'debt', 'savings', 'goals', 'personal', 'investment', 'complete'];

  const _handleNext = () => {
    if (step < steps.length - 1) {
      setStep(step + 1);
    }
  };

  const _handleBack = () => {
    if (step > 0) {
      setStep(step - 1);
    }
  };

  const _handleSubmit = async () => {
    try {
      const _response = await fetch('/api/onboarding/enhanced', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data),
      });

      if (response.ok) {
        router.push('/dashboard');
      } else {
        throw new Error('Failed to save onboarding data');
      }
