      console.error('Onboarding error:', error);
      alert('Failed to save onboarding data. Please try again.');
    }
  };

  const _renderStep = () => {
    switch (steps[step]) {
      case 'income':
        return (
          <Card className="mx-auto w-full max-w-2xl">
            <CardHeader>
              <CardTitle>Income Information</CardTitle>
            </CardHeader>
