    const _age = parseInt(currentAge);
    const _retireAge = parseInt(retirementAge);
    const _savings = parseFloat(currentSavings);
    const _income = parseFloat(monthlyIncome);
    const _returnRate = parseFloat(expectedReturn) / 100;
    const _inflation = parseFloat(inflationRate) / 100;

    if (
      isNaN(age) ||
      isNaN(retireAge) ||
      isNaN(savings) ||
      isNaN(income) ||
      isNaN(returnRate) ||
      isNaN(inflation)
    ) {
      return;
