    const _yearsToRetirement = retireAge - age;
    const _monthlyReturnRate = returnRate / 12;
    const _monthlyInflationRate = inflation / 12;

    // Calculate required monthly contribution
    const _targetIncome = income * 0.8; // 80% of current income
    const _futureValue = targetIncome * 12 * 25; // 25 years of retirement
    const _presentValue = futureValue / Math.pow(1 + inflation, yearsToRetirement);

    const _monthlyContribution =
      (presentValue - savings * Math.pow(1 + returnRate, yearsToRetirement)) /
      ((Math.pow(1 + monthlyReturnRate, yearsToRetirement * 12) - 1) / monthlyReturnRate);

