      monthlyContribution *
        ((Math.pow(1 + monthlyReturnRate, yearsToRetirement * 12) - 1) / monthlyReturnRate);

    const _interestEarned = totalSavings - (savings + monthlyContribution * yearsToRetirement * 12);

    setResults({
      monthlyContribution,
      totalSavings,
      interestEarned,
      yearsToRetirement,
    });
  };

