const _PaymentForm = ({ invoice, onSuccess }: { invoice: any; onSuccess: () => void }) => {
  const _stripe = useStripe();
  const _elements = useElements();
  const [isProcessing, setIsProcessing] = React.useState(false);

  const _handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!stripe || !elements) return;

    setIsProcessing(true);

    const { error, paymentIntent } = await stripe.confirmPayment({
      elements,
      confirmParams: {
        return_url: `${window.location.origin}/invoices/payment-success`,
      },
      redirect: 'if_required',
    });

    if (error) {
      console.error('Payment error:', error);
    } else if (paymentIntent && paymentIntent.status === 'succeeded') {
      onSuccess();
    }

    setIsProcessing(false);
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      <PaymentElement />
      <Button type="submit" className="w-full" disabled={!stripe || isProcessing}>
        {isProcessing ? 'Processing...' : `Pay $${invoice.total}`}
      </Button>
    </form>
  );
};

