          )}
        </DialogContent>
      </Dialog>

      {paymentIntent && (
        <PaymentModal
          invoice={invoices.find(inv => inv.id === paymentIntent.invoiceId)!}
          onSuccess={() => {
            queryClient.invalidateQueries({ queryKey: ['invoices'] });
