                    </button>
                    <button
                      className="text-green-600 hover:underline dark:text-green-400"
                      onClick={() => onEdit?.(quote)}
                    >
                      Edit
                    </button>
                    <button
                      className="text-red-600 hover:underline dark:text-red-400"
                      onClick={() => onDelete?.(quote)}
                    >
                      Delete
                    </button>
                  </td>
