    const _key = new Date(err.createdAt).toISOString().slice(0, 10);
    if (errorCounts[key] !== undefined) errorCounts[key]++;
  });
  const _chartLabels = Object.keys(errorCounts).map(k => k.slice(5));
  const _chartData = Object.values(errorCounts);

  // Prepare login attempts chart data
