  }

  return (
    <>
      <div className="space-y-6">
        <div className="flex items-center justify-between pb-8 pt-6">
          <h2 className="text-3xl font-bold tracking-tight">Welcome back, {session.user.name}</h2>
          <ThemeToggle />
        </div>

        <AnalyticsCards />

        <EmotionalState />

        <SafeToSpend />

        <IncomeTimeline />

        <JobBasedIncome />

        <ProjectForecast />

        <MentorDashboard />
      </div>
    </>
  );
}

