import { useState } from 'react';
import { Card } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Switch } from '@/components/ui/switch';
import { AlertConfig, defaultAlertConfig } from '@/lib/utils/performance-alerts';
import { toast } from 'sonner';

interface AlertSettingsProps {
  onConfigChange: (config: AlertConfig) => void;
  initialConfig?: AlertConfig;
}

export function AlertSettings({
  onConfigChange,
  initialConfig = defaultAlertConfig,
}: AlertSettingsProps) {
  const [config, setConfig] = useState<AlertConfig>(initialConfig);
  const [isEnabled, setIsEnabled] = useState(true);

  const _handleThresholdChange = (
    metric: keyof AlertConfig,
    type: 'warning' | 'error',
    value: string
  ) => {
    const _numValue = parseFloat(value);
    if (isNaN(numValue)) return;

    const _newConfig = {
      ...config,
      [metric]: {
        ...config[metric],
        [type]: numValue,
      },
    };

    setConfig(newConfig);
    onConfigChange(newConfig);
    toast.success('Alert thresholds updated');
  };

  const _handleToggle = (checked: boolean) => {
    setIsEnabled(checked);
    if (!checked) {
      toast.info('Performance alerts disabled');
    } else {
      toast.success('Performance alerts enabled');
    }
  };

  const _handleReset = () => {
    setConfig(defaultAlertConfig);
    onConfigChange(defaultAlertConfig);
    toast.success('Alert thresholds reset to defaults');
  };

  return (
    <Card className="p-6">
      <div className="mb-6 flex items-center justify-between">
        <div>
          <h3 className="text-lg font-semibold">Alert Settings</h3>
          <p className="text-sm text-muted-foreground">Configure performance alert thresholds</p>
        </div>
        <div className="flex items-center gap-4">
          <div className="flex items-center gap-2">
            <Switch checked={isEnabled} onCheckedChange={handleToggle} id="alerts-enabled" />
            <Label htmlFor="alerts-enabled">Enable Alerts</Label>
          </div>
          <Button variant="outline" onClick={handleReset}>
            Reset to Defaults
          </Button>
        </div>
      </div>

      <div className="grid grid-cols-1 gap-6 md:grid-cols-2">
        {Object.entries(config).map(([metric, thresholds]) => (
          <div key={metric} className="space-y-4">
            <h4 className="font-medium capitalize">
              {metric.replace(/([A-Z])/g, ' $1').toLowerCase()}
            </h4>
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor={`${metric}-warning`}>Warning</Label>
                <Input
                  id={`${metric}-warning`}
                  type="number"
                  value={thresholds.warning}
                  onChange={e =>
                    handleThresholdChange(metric as keyof AlertConfig, 'warning', e.target.value)
                  }
                  disabled={!isEnabled}
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor={`${metric}-error`}>Error</Label>
                <Input
                  id={`${metric}-error`}
                  type="number"
                  value={thresholds.error}
                  onChange={e =>
                    handleThresholdChange(metric as keyof AlertConfig, 'error', e.target.value)
                  }
                  disabled={!isEnabled}
                />
              </div>
            </div>
          </div>
        ))}
      </div>
    </Card>
  );
}

import { useMemo, useState } from 'react';
import { _Card } from '@/components/ui/card';
import { Button } from '@/components/ui';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Badge } from '@/components/ui';
import { Download, Filter } from 'lucide-react';
import { _format } from 'date-fns';
import { _Anomaly } from './PerformanceAnomalies.tsx';

interface AnomalyHistoryProps {
  anomalies: Anomaly[];
  onExport?: (anomalies: Anomaly[]) => void;
}

export function AnomalyHistory({ anomalies, onExport }: AnomalyHistoryProps) {
  const [severityFilter, setSeverityFilter] = useState<'all' | 'warning' | 'error'>('all');
  const [metricFilter, setMetricFilter] = useState<string>('all');
  const [typeFilter, setTypeFilter] = useState<'all' | 'spike' | 'drop' | 'trend'>('all');

  const _filteredAnomalies = useMemo(() => {
    return anomalies.filter(anomaly => {
      if (severityFilter !== 'all' && anomaly.severity !== severityFilter) return false;
      if (metricFilter !== 'all' && anomaly.metric !== metricFilter) return false;
      if (typeFilter !== 'all' && anomaly.type !== typeFilter) return false;
      return true;
    });
  }, [anomalies, severityFilter, metricFilter, typeFilter]);

  const _metrics = useMemo(() => {
    return Array.from(new Set(anomalies.map(a => a.metric)));
  }, [anomalies]);

  const _handleExport = () => {
    if (!onExport) return;
    onExport(filteredAnomalies);
  };

  const _stats = useMemo(() => {
    return {
      total: anomalies.length,
      warnings: anomalies.filter(a => a.severity === 'warning').length,
      errors: anomalies.filter(a => a.severity === 'error').length,
      byMetric: metrics.reduce(
        (acc, metric) => {
          acc[metric] = anomalies.filter(a => a.metric === metric).length;
          return acc;
        },
        {} as Record<string, number>
      ),
    };
  }, [anomalies, metrics]);

  return (
    <div className="space-y-6">
      <div className="flex flex-col justify-between gap-4 sm:flex-row">
        <div className="grid grid-cols-1 gap-4 sm:grid-cols-3">
          <Card className="p-4">
            <div className="text-sm text-muted-foreground">Total Anomalies</div>
            <div className="text-2xl font-bold">{stats.total}</div>
          </Card>
          <Card className="p-4">
            <div className="text-sm text-muted-foreground">Warnings</div>
            <div className="text-2xl font-bold text-yellow-600 dark:text-yellow-400">
              {stats.warnings}
            </div>
          </Card>
          <Card className="p-4">
            <div className="text-sm text-muted-foreground">Errors</div>
            <div className="text-2xl font-bold text-red-600 dark:text-red-400">{stats.errors}</div>
          </Card>
        </div>
        <Button
          variant="outline"
          size="sm"
          onClick={handleExport}
          className="flex items-center gap-2"
        >
          <Download className="h-4 w-4" />
          Export CSV
        </Button>
      </div>

      <Card className="p-4">
        <div className="mb-4 flex flex-col gap-4 sm:flex-row">
          <Select value={severityFilter} onValueChange={setSeverityFilter}>
            <SelectTrigger className="w-[180px]">
              <SelectValue placeholder="Filter by severity" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">All Severities</SelectItem>
              <SelectItem value="warning">Warnings</SelectItem>
              <SelectItem value="error">Errors</SelectItem>
            </SelectContent>
          </Select>

          <Select value={metricFilter} onValueChange={setMetricFilter}>
            <SelectTrigger className="w-[180px]">
              <SelectValue placeholder="Filter by metric" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">All Metrics</SelectItem>
              {metrics.map(metric => (
                <SelectItem key={metric} value={metric}>
                  {metric}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>

          <Select value={typeFilter} onValueChange={setTypeFilter}>
            <SelectTrigger className="w-[180px]">
              <SelectValue placeholder="Filter by type" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">All Types</SelectItem>
              <SelectItem value="spike">Spikes</SelectItem>
              <SelectItem value="drop">Drops</SelectItem>
              <SelectItem value="trend">Trends</SelectItem>
            </SelectContent>
          </Select>
        </div>

        <div className="space-y-4">
          {filteredAnomalies.map((anomaly, index) => (
            <div key={index} className="flex items-start justify-between rounded-lg border p-4">
              <div className="flex items-start gap-3">
                <div>
                  <div className="flex items-center gap-2">
                    <span className="font-medium">{anomaly.metric}</span>
                    <Badge variant={anomaly.severity === 'error' ? 'destructive' : 'default'}>
                      {anomaly.severity}
                    </Badge>
                    <Badge variant="outline">{anomaly.type}</Badge>
                  </div>
                  <p className="mt-1 text-sm text-muted-foreground">{anomaly.description}</p>
                  <p className="mt-1 text-xs text-muted-foreground">
                    {format(anomaly.timestamp, 'PPpp')}
                  </p>
                </div>
              </div>
              <div className="text-right">
                <div className="font-medium">{anomaly.value.toFixed(2)}</div>
                <div className="text-sm text-muted-foreground">
                  vs {anomaly.threshold.toFixed(2)}
                </div>
              </div>
            </div>
          ))}

          {filteredAnomalies.length === 0 && (
            <div className="py-8 text-center text-muted-foreground">
              No anomalies match the selected filters
            </div>
          )}
        </div>
      </Card>
    </div>
  );
}

import { _useState } from 'react';
import { _Card } from '@/components/ui/card';
import { Button } from '@/components/ui';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Badge } from '@/components/ui';
import { Textarea } from '@/components/ui';
import { _Input } from '@/components/ui/input';
import { _Label } from '@/components/ui/label';
import { _Anomaly } from './PerformanceAnomalies.tsx';
import { _format } from 'date-fns';
import { CheckCircle2, Clock, AlertCircle, XCircle } from 'lucide-react';

interface Resolution {
  id: string;
  anomalyId: string;
  status: 'open' | 'in_progress' | 'resolved' | 'ignored';
  assignedTo: string;
  notes: string;
  createdAt: Date;
  updatedAt: Date;
  resolutionTime?: number; // Time taken to resolve in minutes
}

interface AnomalyResolutionProps {
  anomalies: Anomaly[];
  onResolutionUpdate?: (resolution: Resolution) => void;
}

export function AnomalyResolution({ anomalies, onResolutionUpdate }: AnomalyResolutionProps) {
  const [resolutions, setResolutions] = useState<Resolution[]>([]);
  const [selectedAnomaly, setSelectedAnomaly] = useState<Anomaly | null>(null);
  const [status, setStatus] = useState<Resolution['status']>('open');
  const [assignedTo, setAssignedTo] = useState('');
  const [notes, setNotes] = useState('');

  const _handleCreateResolution = () => {
    if (!selectedAnomaly) return;

    const resolution: Resolution = {
      id: Math.random().toString(36).substr(2, 9),
      anomalyId: selectedAnomaly.id || Math.random().toString(36).substr(2, 9),
      status,
      assignedTo,
      notes,
      createdAt: new Date(),
      updatedAt: new Date(),
    };

    setResolutions(prev => [...prev, resolution]);
    onResolutionUpdate?.(resolution);
    setSelectedAnomaly(null);
    setStatus('open');
    setAssignedTo('');
    setNotes('');
  };

  const _handleUpdateStatus = (resolutionId: string, newStatus: Resolution['status']) => {
    setResolutions(prev =>
      prev.map(r => {
        if (r.id === resolutionId) {
          const _updated = {
            ...r,
            status: newStatus,
            updatedAt: new Date(),
            ...(newStatus === 'resolved' && {
              resolutionTime: Math.round(
                (new Date().getTime() - r.createdAt.getTime()) / (1000 * 60)
              ),
            }),
          };
          onResolutionUpdate?.(updated);
          return updated;
        }
        return r;
      })
    );
  };

  const _getStatusIcon = (status: Resolution['status']) => {
    switch (status) {
      case 'open':
        return <AlertCircle className="h-4 w-4 text-yellow-500" />;
      case 'in_progress':
        return <Clock className="h-4 w-4 text-blue-500" />;
      case 'resolved':
        return <CheckCircle2 className="h-4 w-4 text-green-500" />;
      case 'ignored':
        return <XCircle className="h-4 w-4 text-gray-500" />;
    }
  };

  const _getStatusColor = (status: Resolution['status']) => {
    switch (status) {
      case 'open':
        return 'bg-yellow-100 text-yellow-800 dark:bg-yellow-900 dark:text-yellow-300';
      case 'in_progress':
        return 'bg-blue-100 text-blue-800 dark:bg-blue-900 dark:text-blue-300';
      case 'resolved':
        return 'bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-300';
      case 'ignored':
        return 'bg-gray-100 text-gray-800 dark:bg-gray-900 dark:text-gray-300';
    }
  };

  return (
    <div className="space-y-6">
      <Card className="p-6">
        <h3 className="mb-4 text-lg font-semibold">Create Resolution</h3>
        <div className="space-y-4">
          <div>
            <Label>Select Anomaly</Label>
            <Select
              value={selectedAnomaly?.id}
              onValueChange={value =>
                setSelectedAnomaly(anomalies.find(a => a.id === value) || null)
              }
            >
              <SelectTrigger>
                <SelectValue placeholder="Select an anomaly" />
              </SelectTrigger>
              <SelectContent>
                {anomalies
                  .filter(a => !resolutions.some(r => r.anomalyId === a.id))
                  .map(anomaly => (
                    <SelectItem key={anomaly.id} value={anomaly.id || ''}>
                      {anomaly.metric} - {anomaly.type} ({anomaly.severity})
                    </SelectItem>
                  ))}
              </SelectContent>
            </Select>
          </div>

          <div>
            <Label>Status</Label>
            <Select
              value={status}
              onValueChange={(value: Resolution['status']) => setStatus(value)}
            >
              <SelectTrigger>
                <SelectValue placeholder="Select status" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="open">Open</SelectItem>
                <SelectItem value="in_progress">In Progress</SelectItem>
                <SelectItem value="resolved">Resolved</SelectItem>
                <SelectItem value="ignored">Ignored</SelectItem>
              </SelectContent>
            </Select>
          </div>

          <div>
            <Label>Assigned To</Label>
            <Input
              value={assignedTo}
              onChange={e => setAssignedTo(e.target.value)}
              placeholder="Enter assignee name"
            />
          </div>

          <div>
            <Label>Notes</Label>
            <Textarea
              value={notes}
              onChange={e => setNotes(e.target.value)}
              placeholder="Add resolution notes..."
            />
          </div>

          <Button onClick={handleCreateResolution} disabled={!selectedAnomaly || !assignedTo}>
            Create Resolution
          </Button>
        </div>
      </Card>

      <Card className="p-6">
        <h3 className="mb-4 text-lg font-semibold">Resolution History</h3>
        <div className="space-y-4">
          {resolutions.map(resolution => {
            const _anomaly = anomalies.find(a => a.id === resolution.anomalyId);
            if (!anomaly) return null;

            return (
              <div
                key={resolution.id}
                className="flex items-start justify-between rounded-lg border p-4"
              >
                <div className="space-y-2">
                  <div className="flex items-center gap-2">
                    {getStatusIcon(resolution.status)}
                    <Badge variant="outline" className={getStatusColor(resolution.status)}>
                      {resolution.status.replace('_', ' ')}
                    </Badge>
                    <span className="font-medium">
                      {anomaly.metric} - {anomaly.type}
                    </span>
                  </div>
                  <p className="text-sm text-muted-foreground">
                    Assigned to: {resolution.assignedTo}
                  </p>
                  {resolution.notes && <p className="text-sm">{resolution.notes}</p>}
                  <div className="text-xs text-muted-foreground">
                    Created: {format(resolution.createdAt, 'PPpp')}
                    {resolution.updatedAt > resolution.createdAt && (
                      <span className="ml-2">Updated: {format(resolution.updatedAt, 'PPpp')}</span>
                    )}
                    {resolution.resolutionTime && (
                      <span className="ml-2">
                        Resolution time: {resolution.resolutionTime} minutes
                      </span>
                    )}
                  </div>
                </div>
                <div className="flex gap-2">
                  {resolution.status !== 'resolved' && (
                    <Button
                      variant="outline"
                      size="sm"
                      onClick={() => handleUpdateStatus(resolution.id, 'resolved')}
                    >
                      Mark Resolved
                    </Button>
                  )}
                  {resolution.status !== 'ignored' && (
                    <Button
                      variant="outline"
                      size="sm"
                      onClick={() => handleUpdateStatus(resolution.id, 'ignored')}
                    >
                      Ignore
                    </Button>
                  )}
                </div>
              </div>
            );
          })}

          {resolutions.length === 0 && (
            <div className="py-8 text-center text-muted-foreground">No resolutions created yet</div>
          )}
        </div>
      </Card>
    </div>
  );
}

import { _useMemo } from 'react';
import { _Card } from '@/components/ui/card';
import { _PerformanceMetric } from '@/lib/utils/performance-alerts';
import { AlertTriangle, TrendingUp, TrendingDown } from 'lucide-react';
import { Badge } from '@/components/ui';

interface PerformanceAnomaliesProps {
  metrics: PerformanceMetric[];
  timeWindow?: '1h' | '6h' | '24h' | '7d';
}

interface Anomaly {
  type: 'spike' | 'drop' | 'trend';
  metric: string;
  value: number;
  threshold: number;
  timestamp: Date;
  severity: 'warning' | 'error';
  description: string;
}

export function PerformanceAnomalies({ metrics, timeWindow = '24h' }: PerformanceAnomaliesProps) {
  const _anomalies = useMemo(() => {
    if (metrics.length < 2) return [];

    const detectedAnomalies: Anomaly[] = [];
    const _metricTypes = ['renderTime', 'updateTime', 'frameTime', 'memoryUsage'];

    metricTypes.forEach(metricType => {
      const _values = metrics.filter(m => m.metricName === metricType).map(m => m.value);

      if (values.length < 2) return;

      // Calculate mean and standard deviation
      const _mean = values.reduce((a, b) => a + b, 0) / values.length;
      const _variance = values.reduce((a, b) => a + Math.pow(b - mean, 2), 0) / values.length;
      const _stdDev = Math.sqrt(variance);

      // Detect spikes and drops (values outside 2 standard deviations)
      values.forEach((value, index) => {
        const _zScore = Math.abs(value - mean) / stdDev;
        if (zScore > 2) {
          const _metric = metrics.find(m => m.metricName === metricType && m.value === value);
          if (!metric) return;

          detectedAnomalies.push({
            type: value > mean ? 'spike' : 'drop',
            metric: metricType,
            value,
            threshold: mean + (value > mean ? 2 : -2) * stdDev,
            timestamp: metric.timestamp,
            severity: zScore > 3 ? 'error' : 'warning',
            description: `${metricType} ${
              value > mean ? 'spiked' : 'dropped'
            } to ${value.toFixed(2)} (${zScore.toFixed(1)}σ from mean)`,
          });
        }
      });

      // Detect trends (3 consecutive increases or decreases)
      for (let i = 2; i < values.length; i++) {
        const _trend = values.slice(i - 2, i + 1);
        const _isIncreasing = trend[0] < trend[1] && trend[1] < trend[2];
        const _isDecreasing = trend[0] > trend[1] && trend[1] > trend[2];

        if (isIncreasing || isDecreasing) {
          const _metric = metrics.find(m => m.metricName === metricType && m.value === trend[2]);
          if (!metric) return;

          detectedAnomalies.push({
            type: 'trend',
            metric: metricType,
            value: trend[2],
            threshold: mean,
            timestamp: metric.timestamp,
            severity: 'warning',
            description: `${metricType} is ${
              isIncreasing ? 'increasing' : 'decreasing'
            } over 3 measurements`,
          });
        }
      }
    });

    return detectedAnomalies.sort((a, b) => b.timestamp.getTime() - a.timestamp.getTime());
  }, [metrics]);

  if (anomalies.length === 0) {
    return (
      <div className="py-8 text-center text-muted-foreground">
        No anomalies detected in the selected time window
      </div>
    );
  }

  return (
    <div className="space-y-4">
      {anomalies.map((anomaly, index) => (
        <Card key={index} className="p-4">
          <div className="flex items-start justify-between">
            <div className="flex items-start gap-3">
              <div
                className={`rounded-full p-2 ${
                  anomaly.severity === 'error'
                    ? 'bg-red-100 dark:bg-red-900/20'
                    : 'bg-yellow-100 dark:bg-yellow-900/20'
                }`}
              >
                {anomaly.type === 'trend' ? (
                  anomaly.value > anomaly.threshold ? (
                    <TrendingUp className="h-5 w-5 text-yellow-600 dark:text-yellow-400" />
                  ) : (
                    <TrendingDown className="h-5 w-5 text-yellow-600 dark:text-yellow-400" />
                  )
                ) : (
                  <AlertTriangle className="h-5 w-5 text-red-600 dark:text-red-400" />
                )}
              </div>
              <div>
                <div className="flex items-center gap-2">
                  <span className="font-medium">{anomaly.metric}</span>
                  <Badge variant={anomaly.severity === 'error' ? 'destructive' : 'default'}>
                    {anomaly.severity}
                  </Badge>
                </div>
                <p className="mt-1 text-sm text-muted-foreground">{anomaly.description}</p>
                <p className="mt-1 text-xs text-muted-foreground">
                  {anomaly.timestamp.toLocaleString()}
