              </div>
            </div>
            <div className="text-right">
              <div className="font-medium">{anomaly.value.toFixed(2)}</div>
              <div className="text-sm text-muted-foreground">vs {anomaly.threshold.toFixed(2)}</div>
            </div>
          </div>
        </Card>
      ))}
    </div>
  );
}

