interface PerformanceTrendsProps {
  metrics: PerformanceMetric[];
  timeWindow?: '1h' | '6h' | '24h' | '7d';
}

export function PerformanceTrends({ metrics, timeWindow = '24h' }: PerformanceTrendsProps) {
  const _filteredMetrics = useMemo(() => {
    const _now = Date.now();
    const _windowMs = {
      '1h': 60 * 60 * 1000,
      '6h': 6 * 60 * 60 * 1000,
      '24h': 24 * 60 * 60 * 1000,
      '7d': 7 * 24 * 60 * 60 * 1000,
    }[timeWindow];

    return metrics.filter(metric => now - new Date(metric.timestamp).getTime() <= windowMs);
  }, [metrics, timeWindow]);

  const _chartData = useMemo(() => {
    const _groupedMetrics = filteredMetrics.reduce(
      (acc, metric) => {
        const _time = format(new Date(metric.timestamp), 'HH:mm');
        if (!acc[time]) {
          acc[time] = {};
        }
        if (!acc[time][metric.metricName]) {
          acc[time][metric.metricName] = [];
        }
        acc[time][metric.metricName].push(metric.value);
        return acc;
      },
      {} as Record<string, Record<string, number[]>>
    );

    const _labels = Object.keys(groupedMetrics).sort();
    const _datasets = ['renderTime', 'updateTime', 'frameTime', 'memoryUsage'].map(metricName => ({
      label: metricName.replace(/([A-Z])/g, ' $1').toLowerCase(),
      data: labels.map(time => {
        const _values = groupedMetrics[time][metricName] || [];
        return values.length ? values.reduce((a, b) => a + b, 0) / values.length : 0;
      }),
      borderColor: getMetricColor(metricName),
      tension: 0.4,
    }));

    return {
      labels,
      datasets,
    };
  }, [filteredMetrics]);

  const _chartOptions = {
    responsive: true,
    plugins: {
      legend: {
        position: 'top' as const,
      },
      title: {
        display: true,
        text: `Performance Trends (${timeWindow})`,
      },
    },
    scales: {
      y: {
        beginAtZero: true,
        ticks: {
          callback: (value: number) => formatMetricValue(value),
        },
      },
    },
  };

  const _trends = useMemo(() => {
    const _calculateTrend = (metricName: string) => {
      const _values = filteredMetrics.filter(m => m.metricName === metricName).map(m => m.value);
      if (values.length < 2) return 0;

      const _firstHalf = values.slice(0, Math.floor(values.length / 2));
      const _secondHalf = values.slice(Math.floor(values.length / 2));
      const _firstAvg = firstHalf.reduce((a, b) => a + b, 0) / firstHalf.length;
      const _secondAvg = secondHalf.reduce((a, b) => a + b, 0) / secondHalf.length;

      return ((secondAvg - firstAvg) / firstAvg) * 100;
    };

    return {
      renderTime: calculateTrend('renderTime'),
      updateTime: calculateTrend('updateTime'),
      frameTime: calculateTrend('frameTime'),
      memoryUsage: calculateTrend('memoryUsage'),
    };
  }, [filteredMetrics]);

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 gap-4 md:grid-cols-2 lg:grid-cols-4">
        {Object.entries(trends).map(([metric, trend]) => (
          <Card key={metric} className="p-4">
            <h4 className="mb-2 text-sm font-medium capitalize">
              {metric.replace(/([A-Z])/g, ' $1').toLowerCase()}
            </h4>
            <div className="flex items-center gap-2">
              <span
                className={`text-lg font-semibold ${trend > 0 ? 'text-red-500' : 'text-green-500'}`}
              >
                {trend > 0 ? '↑' : '↓'} {Math.abs(trend).toFixed(1)}%
              </span>
              <span className="text-sm text-muted-foreground">trend</span>
            </div>
          </Card>
        ))}
      </div>

      <Card className="p-6">
        <Line data={chartData} options={chartOptions} />
      </Card>
    </div>
  );
}

function getMetricColor(metricName: string): string {
  switch (metricName) {
    case 'renderTime':
      return '#5E2DEB';
    case 'updateTime':
      return '#4AE66C';
    case 'frameTime':
      return '#F79C42';
    case 'memoryUsage':
      return '#FF6B6B';
    default:
      return '#9CA3AF';
  }
}

function formatMetricValue(value: number): string {
  if (value >= 1024 * 1024) {
    return `${(value / (1024 * 1024)).toFixed(1)}MB`;
  }
  if (value >= 1024) {
    return `${(value / 1024).toFixed(1)}KB`;
  }
  return `${value.toFixed(1)}ms`;
}

