            'rgba(74, 230, 108, 0.8)',
            'rgba(247, 156, 66, 0.8)',
            'rgba(255, 179, 78, 0.8)',
          ],
        },
      ],
    };
  }, [metrics]);

  return (
    <div className="space-y-6">
      <Tabs defaultValue="histogram" className="w-full">
        <TabsList>
