          <TabsTrigger value="distribution">Distribution</TabsTrigger>
        </TabsList>

        <TabsContent value="histogram">
          <Card className="p-6">
            <h3 className="mb-4 text-lg font-semibold">Render Time Distribution</h3>
            <div className="h-[400px]">
              <Bar
                data={histogramData}
                options={{
                  responsive: true,
                  maintainAspectRatio: false,
                  scales: {
                    y: {
                      beginAtZero: true,
                      title: {
                        display: true,
                        text: 'Frequency',
                      },
                    },
                    x: {
                      title: {
                        display: true,
                        text: 'Render Time (ms)',
                      },
                    },
                  },
                }}
              />
            </div>
          </Card>
        </TabsContent>

        <TabsContent value="heatmap">
          <Card className="p-6">
            <h3 className="mb-4 text-lg font-semibold">Performance Heatmap</h3>
            <div className="h-[400px]">
              <Bar
                data={heatmapData}
                options={{
                  responsive: true,
                  maintainAspectRatio: false,
                  scales: {
                    y: {
                      beginAtZero: true,
                      title: {
                        display: true,
                        text: 'Day',
                      },
                    },
                    x: {
                      title: {
                        display: true,
                        text: 'Hour',
                      },
