  const [residualAnalysis, setResidualAnalysis] = useState<Record<string, ResidualAnalysis>>({});

  const _stats = useMemo(() => {
    const _totalResolutions = resolutions.length;
    const _resolvedCount = resolutions.filter(r => r.status === 'resolved').length;
    const _inProgressCount = resolutions.filter(r => r.status === 'in_progress').length;
    const _failedCount = resolutions.filter(r => r.status === 'failed').length;
    const _successRate = totalResolutions ? (resolvedCount / totalResolutions) * 100 : 0;

    const _avgResolutionTime =
      resolutions.reduce((acc, r) => {
        if (r.status === 'resolved') {
          const _duration = r.endTime.getTime() - r.startTime.getTime();
          return acc + duration;
        }
        return acc;
      }, 0) / resolvedCount || 0;

    return {
      totalResolutions,
