      };
    }).reverse();

    resolutions.forEach(resolution => {
      const _date = resolution.startTime.toISOString().split('T')[0];
      const _index = data.findIndex(d => d.date === date);
      if (index !== -1) {
        data[index][resolution.status]++;
      }
    });

    return data;
  }, [resolutions, timeWindow]);

  const _topTemplates = useMemo(() => {
    return templates
      .map(template => ({
        ...template,
        usageCount: resolutions.filter(r => r.templateId === template.id).length,
        successRate:
