  const _resolutionTimeData = useMemo(() => {
    const _timeMap = new Map<string, number[]>();

    resolutions.forEach(resolution => {
      if (resolution.status === 'resolved') {
        const _template = templates.find(t => t.id === resolution.templateId);
        if (!template) return;

        const _duration = resolution.endTime.getTime() - resolution.startTime.getTime();
        const _times = timeMap.get(template.category) || [];
        times.push(duration / (1000 * 60)); // Convert to minutes
        timeMap.set(template.category, times);
      }
    });

    return Array.from(timeMap.entries()).map(([category, times]) => ({
      category,
      min: Math.min(...times),
      max: Math.max(...times),
      avg: times.reduce((a, b) => a + b, 0) / times.length,
      median: times.sort((a, b) => a - b)[Math.floor(times.length / 2)],
    }));
  }, [templates, resolutions]);

  const _trendData = useMemo(() => {
    const _now = new Date();
    const _days =
      timeWindow === '7d' ? 7 : timeWindow === '30d' ? 30 : timeWindow === '90d' ? 90 : 365;
    const _data = Array.from({ length: days }, (_, i) => {
      const _date = new Date(now);
      date.setDate(date.getDate() - i);
      return {
        date: date.toISOString().split('T')[0],
        successRate: 0,
        avgResolutionTime: 0,
        resolutionCount: 0,
      };
    }).reverse();

    // Calculate daily metrics
    resolutions.forEach(resolution => {
      const _date = resolution.startTime.toISOString().split('T')[0];
      const _index = data.findIndex(d => d.date === date);
      if (index !== -1) {
        data[index].resolutionCount++;
        if (resolution.status === 'resolved') {
          const _duration = resolution.endTime.getTime() - resolution.startTime.getTime();
          data[index].avgResolutionTime =
            (data[index].avgResolutionTime * (data[index].resolutionCount - 1) + duration) /
            data[index].resolutionCount;
          data[index].successRate =
            (data[index].successRate * (data[index].resolutionCount - 1) + 100) /
            data[index].resolutionCount;
        }
      }
    });

    // Calculate moving averages
    const _windowSize = 3;
    return data.map((day, index) => {
      const _start = Math.max(0, index - windowSize + 1);
      const _window = data.slice(start, index + 1);
      const _avgSuccessRate = window.reduce((sum, d) => sum + d.successRate, 0) / window.length;
      const _avgResolutionTime =
        window.reduce((sum, d) => sum + d.avgResolutionTime, 0) / window.length;
      const _trend = index > 0 ? day.successRate - data[index - 1].successRate : 0;

      return {
        ...day,
        avgSuccessRate,
        avgResolutionTime: avgResolutionTime / (1000 * 60), // Convert to minutes
        trend,
      };
    });
  }, [resolutions, timeWindow]);

  const _predictiveMetrics = useMemo(() => {
    const _recentResolutions = resolutions.filter(
      r => r.startTime > new Date(Date.now() - 7 * 24 * 60 * 60 * 1000)
    );

    const _categoryTrends = new Map<string, { count: number; avgTime: number }>();
    recentResolutions.forEach(resolution => {
      const _template = templates.find(t => t.id === resolution.templateId);
      if (!template) return;

      const _existing = categoryTrends.get(template.category) || {
        count: 0,
        avgTime: 0,
      };
      const _duration = resolution.endTime.getTime() - resolution.startTime.getTime();
      categoryTrends.set(template.category, {
        count: existing.count + 1,
        avgTime: (existing.avgTime * existing.count + duration) / (existing.count + 1),
      });
    });

    return Array.from(categoryTrends.entries()).map(([category, data]) => ({
      category,
      frequency: data.count / 7, // Issues per day
      avgResolutionTime: data.avgTime / (1000 * 60), // Convert to minutes
      risk: data.count > 3 ? 'high' : data.count > 1 ? 'medium' : 'low',
    }));
