  const _handleExport = async (config: ExportConfig) => {
    const _data = {
      metrics: customMetrics.reduce(
        (acc, metric) => {
          acc[metric.name] = calculateCustomMetric(metric, drillDownData);
          return acc;
        },
        {} as Record<string, number>
