  const _calculateMovingAverage = (data: any[], windowSize: number) => {
    return data.map((_, index) => {
      const _start = Math.max(0, index - windowSize + 1);
      const _window = data.slice(start, index + 1);
      const _sum = window.reduce((acc, d) => acc + d[selectedMetric], 0);
      return {
        date: data[index].date,
        trend: sum / window.length,
      };
    });
  };

  const _calculatePolynomialRegression = (data: any[], degree: number) => {
    const _xValues = data.map((_, i) => i);
    const _yValues = data.map(d => d[selectedMetric]);
    const _n = xValues.length;

    // Create the design matrix
    const _X = xValues.map(x => {
      const _row = [1];
      for (let i = 1; i <= degree; i++) {
        row.push(Math.pow(x, i));
      }
      return row;
    });

    // Calculate coefficients using least squares
    const _XT = X[0].map((_, i) => X.map(row => row[i]));
    const _XTX = XT.map(row =>
      X[0].map((_, i) => row.reduce((sum, val, j) => sum + val * X[j][i], 0))
    );
    const _XTy = XT.map(row => row.reduce((sum, val, i) => sum + val * yValues[i], 0));

    // Solve the system of equations
    const _coefficients = solveLinearSystem(XTX, XTy);

    // Generate trend line points
    return data.map((d, i) => ({
      date: d.date,
      trend: coefficients.reduce((sum, coef, j) => sum + coef * Math.pow(i, j), 0),
    }));
  };

  const _solveLinearSystem = (A: number[][], b: number[]) => {
    const _n = A.length;
    const _augmented = A.map((row, i) => [...row, b[i]]);

    // Gaussian elimination
    for (let i = 0; i < n; i++) {
      let maxRow = i;
      for (let j = i + 1; j < n; j++) {
        if (Math.abs(augmented[j][i]) > Math.abs(augmented[maxRow][i])) {
          maxRow = j;
        }
      }
      [augmented[i], augmented[maxRow]] = [augmented[maxRow], augmented[i]];

      for (let j = i + 1; j < n; j++) {
        const _factor = augmented[j][i] / augmented[i][i];
        for (let k = i; k <= n; k++) {
          augmented[j][k] -= factor * augmented[i][k];
        }
      }
    }

    // Back substitution
    const _x = new Array(n).fill(0);
    for (let i = n - 1; i >= 0; i--) {
      let sum = augmented[i][n];
      for (let j = i + 1; j < n; j++) {
        sum -= augmented[i][j] * x[j];
      }
      x[i] = sum / augmented[i][i];
    }

    return x;
  };

