  // Detect seasonality using autocorrelation
  const _detectSeasonality = (data: any[]) => {
    const _values = data.map(d => d[selectedMetric]);
    const _n = values.length;
    const _maxLag = Math.min(n - 1, 30);

    // Calculate autocorrelation
    const _autocorr = Array(maxLag + 1)
      .fill(0)
      .map((_, lag) => {
        const _mean = values.reduce((a, b) => a + b, 0) / n;
        const _variance = values.reduce((a, b) => a + Math.pow(b - mean, 2), 0) / n;

        let numerator = 0;
        for (let i = 0; i < n - lag; i++) {
          numerator += (values[i] - mean) * (values[i + lag] - mean);
        }

        return numerator / (n * variance);
      });

    // Find all significant peaks
    const _peaks = autocorr
      .map((value, index) => ({ value, index }))
      .filter((point, i, arr) => {
        if (i === 0 || i === arr.length - 1) return false;
        return (
          point.value > arr[i - 1].value && point.value > arr[i + 1].value && point.value > 0.3 // Lower threshold to detect multiple periods
        );
      })
      .sort((a, b) => b.value - a.value);

    if (peaks.length === 0) return null;

    // Calculate seasonal patterns for each period
    const _periods = peaks.slice(0, 3).map(peak => {
      const _period = peak.index;
      const _pattern = Array(period)
        .fill(0)
        .map((_, i) => {
          const _seasonalValues = values.filter((_, j) => j % period === i);
          return seasonalValues.reduce((a, b) => a + b, 0) / seasonalValues.length;
        });

      return {
        period,
        strength: peak.value / (1 + peak.value),
        pattern,
      };
    });

    return {
      periods,
      dominantPeriod: periods[0].period,
    };
  };

  // Exponential Smoothing Forecast
  const _generateExponentialForecast = (data: any[], periods: number) => {
    const _values = data.map(d => d[selectedMetric]);
    const _n = values.length;
    const _lastDate = new Date(data[n - 1].date);

    // Initialize components
    const _level = values[0];
    const _trend = (values[n - 1] - values[0]) / (n - 1);
    const _seasonal = Array(12).fill(0); // Assuming monthly seasonality

    // Calculate initial seasonal components
    for (let i = 0; i < 12; i++) {
      const _seasonalValues = values.filter((_, j) => j % 12 === i);
      seasonal[i] = seasonalValues.reduce((a, b) => a + b, 0) / seasonalValues.length - level;
    }

    // Generate forecast
    const forecast: Forecast[] = [];
    for (let i = 1; i <= periods; i++) {
      const _forecastDate = new Date(lastDate);
      forecastDate.setDate(forecastDate.getDate() + i);

      // Update components
      const _seasonalIndex = (n + i - 1) % 12;
      const _forecastValue = level + trend * i + seasonal[seasonalIndex];

      // Calculate confidence intervals
      const _standardError = calculateStandardError(values, forecastValue);
      const _zScore = calculateZScore(confidenceLevel);
      const _margin = zScore * standardError * Math.sqrt(i);

      forecast.push({
        date: forecastDate.toISOString().split('T')[0],
        value: forecastValue,
        lowerBound: forecastValue - margin,
        upperBound: forecastValue + margin,
        components: {
          trend: level + trend * i,
          seasonal: seasonal[seasonalIndex],
          residual: 0,
        },
      });
    }

    return forecast;
  };

  // ARIMA Forecast
  const _generateARIMAForecast = (data: any[], periods: number) => {
    const _values = data.map(d => d[selectedMetric]);
    const _n = values.length;
    const _lastDate = new Date(data[n - 1].date);

    // Difference the series
    const _diff = (x: number[]) => {
      const _result = [];
      for (let i = 1; i < x.length; i++) {
        result.push(x[i] - x[i - 1]);
      }
      return result;
    };

    // Calculate AR coefficients
    const _calculateARCoefficients = (x: number[], p: number) => {
      const _n = x.length;
      const _r = Array(p + 1).fill(0);

      // Calculate autocorrelations
      for (let k = 0; k <= p; k++) {
        let numerator = 0;
        let denominator = 0;
        for (let i = 0; i < n - k; i++) {
          numerator += x[i] * x[i + k];
          denominator += x[i] * x[i];
        }
        r[k] = numerator / denominator;
      }

      // Solve Yule-Walker equations
      const _R = Array(p)
        .fill(0)
        .map(() => Array(p).fill(0));
      const _r_vec = Array(p).fill(0);

      for (let i = 0; i < p; i++) {
        for (let j = 0; j < p; j++) {
          R[i][j] = r[Math.abs(i - j)];
        }
        r_vec[i] = r[i + 1];
      }

      return solveLinearSystem(R, r_vec);
    };

    // Generate forecast
    const forecast: Forecast[] = [];
    const _diffed = diff(values);
    const _arCoeffs = calculateARCoefficients(diffed, forecastModel.p || 2);

    for (let i = 1; i <= periods; i++) {
      const _forecastDate = new Date(lastDate);
      forecastDate.setDate(forecastDate.getDate() + i);

      // Calculate forecast value
      let forecastValue = values[n - 1];
      for (let j = 0; j < arCoeffs.length; j++) {
        forecastValue += arCoeffs[j] * (values[n - 1 - j] - values[n - 2 - j]);
      }

      // Calculate confidence intervals
      const _standardError = calculateStandardError(values, forecastValue);
      const _zScore = calculateZScore(confidenceLevel);
      const _margin = zScore * standardError * Math.sqrt(i);

      forecast.push({
        date: forecastDate.toISOString().split('T')[0],
        value: forecastValue,
        lowerBound: forecastValue - margin,
        upperBound: forecastValue + margin,
      });
    }

    return forecast;
  };

  // Enhanced forecast generation
