  // Calculate model performance metrics
  const _calculateModelMetrics = (
    actual: number[],
    predicted: number[],
    model: ForecastModel
  ): ModelMetrics => {
    const _n = actual.length;

    // Calculate basic error metrics
    const _errors = actual.map((a, i) => a - predicted[i]);
    const _mae = errors.reduce((sum, e) => sum + Math.abs(e), 0) / n;
    const _mse = errors.reduce((sum, e) => sum + e * e, 0) / n;
    const _rmse = Math.sqrt(mse);
    const _mape = (errors.reduce((sum, e, i) => sum + Math.abs(e / actual[i]), 0) / n) * 100;

    // Calculate information criteria
    const _k = model.type === 'arima' ? (model.p || 0) + (model.q || 0) + 1 : 3; // Number of parameters
    const _aic = n * Math.log(mse) + 2 * k;
    const _bic = n * Math.log(mse) + k * Math.log(n);

    return { mae, mse, rmse, mape, aic, bic };
  };

