  // Shapiro-Wilk test for normality
  const _performShapiroWilkTest = (residuals: number[]): StatisticalTest => {
    const _n = residuals.length;
    const _sortedResiduals = [...residuals].sort((a, b) => a - b);

    // Calculate W statistic
    let numerator = 0;
    let denominator = 0;

    for (let i = 0; i < n; i++) {
      const _ai = calculateShapiroWilkCoefficient(n, i);
      numerator += ai * (sortedResiduals[n - 1 - i] - sortedResiduals[i]);
      denominator += Math.pow(residuals[i] - residuals.reduce((a, b) => a + b) / n, 2);
    }

    const _W = Math.pow(numerator, 2) / denominator;

    // Approximate p-value
    const _pValue = calculateShapiroWilkPValue(W, n);

    return {
      name: 'Shapiro-Wilk Test',
      statistic: W,
      pValue,
      conclusion: pValue > 0.05 ? 'Residuals appear normal' : 'Residuals are not normal',
    };
  };

  // Durbin-Watson test for autocorrelation
  const _performDurbinWatsonTest = (residuals: number[]): StatisticalTest => {
    let d = 0;
    for (let i = 1; i < residuals.length; i++) {
      d += Math.pow(residuals[i] - residuals[i - 1], 2);
    }
    d /= residuals.reduce((sum, r) => sum + r * r, 0);

    // Approximate p-value
    const _pValue = calculateDurbinWatsonPValue(d, residuals.length);

    return {
      name: 'Durbin-Watson Test',
      statistic: d,
      pValue,
      conclusion:
        pValue > 0.05 ? 'No significant autocorrelation' : 'Significant autocorrelation present',
    };
  };

  // Breusch-Pagan test for heteroscedasticity
  const _performBreuschPaganTest = (residuals: number[]): StatisticalTest => {
    const _n = residuals.length;
    const _squaredResiduals = residuals.map(r => r * r);
    const _meanSquaredResidual = squaredResiduals.reduce((a, b) => a + b) / n;

    // Calculate LM statistic
    const _LM =
      n *
      Math.pow(
        squaredResiduals.reduce((sum, r, i) => sum + (r - meanSquaredResidual) * i, 0) /
          squaredResiduals.reduce((sum, r) => sum + Math.pow(r - meanSquaredResidual, 2), 0),
        2
      );

    // Approximate p-value
    const _pValue = calculateBreuschPaganPValue(LM);

    return {
      name: 'Breusch-Pagan Test',
      statistic: LM,
      pValue,
      conclusion:
        pValue > 0.05 ? 'No significant heteroscedasticity' : 'Heteroscedasticity present',
    };
  };

