  const _detectResidualOutliers = (residuals: number[]) => {
    const _sortedResiduals = [...residuals].sort((a, b) => a - b);
    const _q1 = sortedResiduals[Math.floor(residuals.length * 0.25)];
    const _q3 = sortedResiduals[Math.floor(residuals.length * 0.75)];
    const _iqr = q3 - q1;
    const _threshold = 1.5 * iqr;

    const _outliers = residuals
      .map((r, i) => ({ value: r, index: i }))
      .filter(({ value }) => Math.abs(value) > threshold);

    return {
