  // Jarque-Bera test for normality
  const _performJarqueBeraTest = (residuals: number[]): StatisticalTest => {
    const _n = residuals.length;
    const _mean = residuals.reduce((a, b) => a + b) / n;
    const _variance = residuals.reduce((a, b) => a + Math.pow(b - mean, 2), 0) / n;

    // Calculate skewness and kurtosis
    const _skewness =
      residuals.reduce((a, b) => a + Math.pow(b - mean, 3), 0) / (n * Math.pow(variance, 1.5));
    const _kurtosis =
      residuals.reduce((a, b) => a + Math.pow(b - mean, 4), 0) / (n * Math.pow(variance, 2)) - 3;

    const _JB = n * (Math.pow(skewness, 2) / 6 + Math.pow(kurtosis, 2) / 24);

    // Approximate p-value
    const _pValue = calculateChiSquarePValue(JB, 2);

    return {
      name: 'Jarque-Bera Test',
