    const _sumSquared = partialSums.reduce((sum, x) => sum + x * x, 0);
    const _variance = demeaned.reduce((sum, x) => sum + x * x, 0) / n;
    const _kpss = sumSquared / (n * n * variance);

    // Critical values for KPSS test
    const _criticalValues = {
      '1%': 0.739,
