  const _performARCHTest = (residuals: number[]): StatisticalTest => {
    const _n = residuals.length;
    const _squaredResiduals = residuals.map(x => x * x);
    const _meanSquared = squaredResiduals.reduce((a, b) => a + b) / n;

    // Calculate ARCH statistic
    let numerator = 0;
    let denominator = 0;

    for (let i = 1; i < n; i++) {
      numerator += Math.pow(squaredResiduals[i] - meanSquared, 2);
      denominator += Math.pow(squaredResiduals[i - 1] - meanSquared, 2);
