                  <div>
                    <h6 className="mb-2 text-xs font-medium">Heteroscedasticity Test</h6>
                    <div className="space-y-1">
                      <p className="text-xs text-muted-foreground">
                        {residualAnalysis[comparison.model.type]?.heteroscedasticity.name}
