                                lag: x,
                                acf: residualAnalysis[comparison.model.type]?.ljungBox.distribution
                                  ?.y[i],
                              }))}
                            >
                              <XAxis dataKey="lag" />
                              <YAxis />
                              <Tooltip />
                              <Line type="monotone" dataKey="acf" stroke="#8884d8" />
                              <ReferenceLine y={0} stroke="#666" />
                            </LineChart>
                          </ResponsiveContainer>
                        </div>
                      )}
                    </div>
                  </div>

                  <div>
                    <h6 className="mb-2 text-xs font-medium">Jarque-Bera Test</h6>
                    <div className="space-y-1">
                      <p className="text-xs text-muted-foreground">
                        {residualAnalysis[comparison.model.type]?.jarqueBera.name}
                      </p>
                      <p className="text-sm">
                        Statistic:{' '}
                        {residualAnalysis[comparison.model.type]?.jarqueBera.statistic.toFixed(3)}
                      </p>
                      <p className="text-sm">
                        p-value:{' '}
                        {residualAnalysis[comparison.model.type]?.jarqueBera.pValue.toFixed(3)}
                      </p>
                      <p
                        className={`text-sm ${
