                            fill={COLORS[index]}
                            fillOpacity={0.6}
                          />
                          <Line
                            x1={0}
                            x2={100}
                            y1={residualAnalysis[comparison.model.type]?.boxPlot?.median}
                            y2={residualAnalysis[comparison.model.type]?.boxPlot?.median}
                            stroke="#000"
                            strokeWidth={2}
                          />
                          <Line
                            x1={50}
                            x2={50}
                            y1={residualAnalysis[comparison.model.type]?.boxPlot?.min}
                            y2={residualAnalysis[comparison.model.type]?.boxPlot?.max}
