                          {residualAnalysis[comparison.model.type]?.boxPlot?.outliers.map(
                            (outlier, i) => (
                              <Scatter key={i} data={[{ x: 50, y: outlier }]} fill="#ff0000" />
                            )
                          )}
                        </ComposedChart>
                      </ResponsiveContainer>
                    </div>
                  </div>
                </div>
              </div>
            )}
          </Card>
        ))}
      </div>
    </div>
