interface Resource {
  id: string;
  title: string;
  description: string;
  type: 'article' | 'video' | 'course' | 'podcast';
  duration?: string;
  level: 'beginner' | 'intermediate' | 'advanced';
  category: string;
  url: string;
}

interface FinancialEducationProps {
  resources?: Resource[];
  onResourceClick?: (resource: Resource) => void;
}

export default function FinancialEducation({
