  onResourceClick,
}: FinancialEducationProps) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedType, setSelectedType] = useState<string>('all');
  const [selectedLevel, setSelectedLevel] = useState<string>('all');

  const _filteredResources = resources.filter(resource => {
    const _matchesSearch =
      resource.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
      resource.description.toLowerCase().includes(searchQuery.toLowerCase());
    const _matchesType = selectedType === 'all' || resource.type === selectedType;
    const _matchesLevel = selectedLevel === 'all' || resource.level === selectedLevel;
    return matchesSearch && matchesType && matchesLevel;
  });

  const _getTypeIcon = (type: Resource['type']) => {
    switch (type) {
      case 'article':
        return '📄';
      case 'video':
        return '🎥';
      case 'course':
        return '📚';
      case 'podcast':
        return '🎧';
      default:
        return '📄';
    }
  };

  const _getLevelColor = (level: Resource['level']) => {
    switch (level) {
      case 'beginner':
        return 'bg-green-500';
      case 'intermediate':
        return 'bg-blue-500';
      case 'advanced':
        return 'bg-purple-500';
      default:
        return 'bg-gray-500';
    }
  };

  return (
    <Card className="p-6">
      <div className="mb-6 flex items-center justify-between">
        <h2 className="text-2xl font-bold">Financial Education</h2>
        <Input
          placeholder="Search resources..."
          value={searchQuery}
          onChange={e => setSearchQuery(e.target.value)}
          className="max-w-xs"
        />
      </div>

