interface Insight {
  id: string;
  title: string;
  description: string;
  category: string;
  impact: 'high' | 'medium' | 'low';
  date: Date;
  type: 'saving' | 'investment' | 'spending' | 'income';
}

interface FinancialInsightsProps {
  insights?: Insight[];
  onInsightClick?: (insight: Insight) => void;
}

export default function FinancialInsights({
  insights = [],
  onInsightClick,
}: FinancialInsightsProps) {
  const [selectedTab, setSelectedTab] = useState<string>('all');

  const _filteredInsights =
    selectedTab === 'all' ? insights : insights.filter(insight => insight.type === selectedTab);

  const _getImpactColor = (impact: Insight['impact']) => {
    switch (impact) {
      case 'high':
        return 'bg-red-500';
      case 'medium':
        return 'bg-yellow-500';
      case 'low':
        return 'bg-green-500';
      default:
        return 'bg-gray-500';
    }
  };

  const _getTypeIcon = (type: Insight['type']) => {
    switch (type) {
      case 'saving':
        return '💰';
      case 'investment':
        return '📈';
      case 'spending':
        return '💸';
      case 'income':
        return '💵';
      default:
        return '📊';
    }
  };

  return (
    <Card className="p-6">
      <div className="mb-6 flex items-center justify-between">
        <h2 className="text-2xl font-bold">Financial Insights</h2>
