function mockFetch(data: any, delay = 0) {
  return jest.fn().mockImplementation(
    () =>
      new Promise(resolve =>
        setTimeout(
          () =>
            resolve({
              ok: true,
              json: async () => data,
            }),
          delay
        )
      )
  );
}

