const _goalSchema = z.object({
  title: z.string().min(1, 'Title is required'),
  targetAmount: z.string().min(1, 'Target amount is required'),
  currentAmount: z.string().min(1, 'Current amount is required'),
  deadline: z.string().min(1, 'Deadline is required'),
  category: z.string().min(1, 'Category is required'),
});

type GoalFormValues = z.infer<typeof goalSchema>;

interface GoalDialogProps {
  mode: 'add' | 'edit';
  goal?: {
    id: string;
    title: string;
    targetAmount: number;
    currentAmount: number;
    deadline: string;
    category: string;
  };
  onSubmit: (data: GoalFormValues) => void;
}

const _categories = ['Savings', 'Major Purchase', 'Travel', 'Education', 'Investment', 'Other'];

export function GoalDialog({ mode, goal, onSubmit }: GoalDialogProps) {
  const [open, setOpen] = useState(false);

  const _form = useForm<GoalFormValues>({
    resolver: zodResolver(goalSchema),
    defaultValues: goal
      ? {
          title: goal.title,
          targetAmount: goal.targetAmount.toString(),
          currentAmount: goal.currentAmount.toString(),
          deadline: goal.deadline,
          category: goal.category,
        }
      : {
          title: '',
          targetAmount: '',
          currentAmount: '',
          deadline: '',
          category: '',
        },
  });

  const _handleSubmit = (data: GoalFormValues) => {
    onSubmit(data);
    setOpen(false);
    form.reset();
  };

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        <Button>
          <Icons.plus className="mr-2 h-4 w-4" />
