                        <Input
                          type="number"
                          placeholder="Duration"
                          min={1}
                          value={durationValue}
                          onChange={e => {
                            // Only allow positive numbers
                            const _val = e.target.value;
                            if (/^\d*$/.test(val) && Number(val) > 0) {
                              setDurationValue(val);
                              if (durationUnit) {
                                form.setValue('duration', `${val} ${durationUnit}`);
                              }
                            } else if (val === '') {
                              setDurationValue('');
                              form.setValue('duration', '');
                            }
                          }}
                          className="w-24"
                          inputMode="numeric"
                          pattern="[0-9]*"
                          aria-label="Duration value"
                        />
                      </FormControl>
                      <Select
                        value={durationUnit}
                        onValueChange={value => {
                          setDurationUnit(value);
                          if (durationValue) {
                            form.setValue('duration', `${durationValue} ${value}`);
                          }
                        }}
                      >
                        <FormControl>
                          <SelectTrigger className="w-32">
                            <SelectValue placeholder="Unit" />
                          </SelectTrigger>
                        </FormControl>
                        <SelectContent>
                          {durationUnits.map(unit => (
                            <SelectItem key={unit.value} value={unit.value}>
                              {unit.label}
                            </SelectItem>
                          ))}
                        </SelectContent>
                      </Select>
                    </div>
                    <FormMessage />
                  </FormItem>
                )}
              />
            </div>

            <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
              <FormField
                control={form.control}
                name="price"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Price ($)</FormLabel>
                    <FormControl>
                      <Input
                        type="number"
                        placeholder="0.00"
                        {...field}
                        onChange={e => field.onChange(parseFloat(e.target.value))}
                      />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              <FormField
                control={form.control}
                name="tags"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Tags (comma-separated)</FormLabel>
                    <FormControl>
                      <Input placeholder="e.g., web, design, marketing" {...field} />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />
            </div>

            <FormField
              control={form.control}
              name="isProOnly"
              render={({ field }) => (
                <FormItem className="flex items-center gap-2">
                  <FormControl>
                    <input
                      type="checkbox"
                      checked={field.value}
                      onChange={field.onChange}
                      className="h-4 w-4 rounded border-gray-300"
                      aria-label="Pro Only Service"
                    />
                  </FormControl>
                  <FormLabel className="!mt-0">Pro Only Service</FormLabel>
                  <FormMessage />
                </FormItem>
              )}
            />

            <div className="sticky bottom-0 flex flex-col justify-end gap-4 border-t bg-background pt-4 sm:flex-row">
              <Button
                type="button"
                variant="outline"
                onClick={() => setOpen(false)}
                className="w-full sm:w-auto"
              >
                Cancel
              </Button>
              <Button type="submit" disabled={isLoading} className="w-full sm:w-auto">
                {isLoading ? 'Creating...' : 'Create Service'}
              </Button>
            </div>
          </form>
        </Form>
      </DialogContent>
    </Dialog>
  );
}

