  const _sortedAndFilteredTemplates = filteredTemplates.sort((a, b) => {
    const _direction = sortDirection === 'asc' ? 1 : -1;
    switch (sortField) {
      case 'name':
        return direction * a.name.localeCompare(b.name);
      case 'type':
        return direction * a.type.localeCompare(b.type);
