    try {
      const _templates = savedTemplates.filter(t => selectedTemplates.has(t.id));
      const _zip = new JSZip();

      // Add each template to the zip
      await Promise.all(
        templates.map(async template => {
          const _blob = exportTemplate(template);
          const _content = await blob.text();
          zip.file(`${template.name.toLowerCase().replace(/\s+/g, '-')}-template.json`, content);
        })
      );

      // Generate and download zip
      const _zipBlob = await zip.generateAsync({ type: 'blob' });
      const _url = URL.createObjectURL(zipBlob);
      const _a = document.createElement('a');
      a.href = url;
      a.download = 'templates.zip';
