                                    className="space-y-2 rounded-md border p-2"
                                  >
                                    <div className="flex items-center justify-between">
                                      <div className="flex items-center space-x-2">
                                        <Checkbox
                                          checked={selectedTemplates.has(template.id)}
                                          onCheckedChange={checked => {
                                            setSelectedTemplates(prev => {
                                              const _next = new Set(prev);
                                              if (checked) {
                                                next.add(template.id);
                                              } else {
                                                next.delete(template.id);
                                              }
                                              return next;
                                            });
                                          }}
                                        />
                                        <div className="space-y-1">
                                          <p className="text-sm font-medium">{template.name}</p>
                                          <p className="text-xs text-muted-foreground">
                                            {template.type} • {template.format}
                                            {template.category && ` • ${template.category}`}
                                          </p>
                                          {template.tags.length > 0 && (
                                            <div className="flex flex-wrap gap-1">
                                              {template.tags.map(tag => (
                                                <Badge key={tag} variant="secondary">
                                                  {tag}
                                                </Badge>
                                              ))}
                                            </div>
                                          )}
                                        </div>
                                      </div>
                                      <div className="flex items-center space-x-2">
                                        <Button
                                          variant="ghost"
                                          size="sm"
                                          onClick={() => handleLoadTemplate(template)}
                                        >
                                          <Icons.load className="h-4 w-4" />
                                        </Button>
                                        <Button
                                          variant="ghost"
                                          size="sm"
                                          onClick={() => handleExportTemplate(template)}
                                          disabled={isExporting}
                                        >
                                          {isExporting && (
                                            <Icons.spinner className="mr-2 h-4 w-4 animate-spin" />
                                          )}
                                          <Icons.download className="h-4 w-4" />
                                        </Button>
                                        <Button
                                          variant="ghost"
                                          size="sm"
                                          onClick={() => handleDeleteTemplate(template.id)}
                                        >
                                          <Icons.trash className="h-4 w-4" />
                                        </Button>
                                      </div>
                                    </div>
                                    <div className="flex items-center justify-between border-t pt-2">
                                      <div className="flex items-center space-x-2">
                                        <Switch
                                          id={`public-${template.id}`}
                                          checked={template.isPublic}
                                          onCheckedChange={checked =>
                                            handleUpdateVisibility(template.id, checked)
                                          }
                                        />
                                        <label
                                          htmlFor={`public-${template.id}`}
                                          className="text-xs text-muted-foreground"
                                        >
                                          Public
                                        </label>
                                      </div>
                                      <div className="flex items-center space-x-2">
                                        {template.sharedWith.length > 0 && (
                                          <Badge variant="secondary" className="text-xs">
                                            {template.sharedWith.length} shared
                                          </Badge>
                                        )}
                                        <Button
                                          variant="ghost"
                                          size="sm"
                                          onClick={() => {
                                            setSelectedTemplateForSharing(template);
                                            setShareDialogOpen(true);
                                          }}
                                        >
                                          <Icons.share className="h-4 w-4" />
                                        </Button>
                                      </div>
                                    </div>

                                    {selectedTemplate?.id === template.id && (
                                      <div className="mt-2 space-y-2 border-t pt-2">
                                        <TemplateVersionDiff
                                          versions={templateVersions}
                                          onRestore={handleRestoreVersion}
                                          isRestoring={isRestoringVersion}
                                        />
                                      </div>
                                    )}
                                  </div>
                                ))
                              )}
                            </div>
                          </div>
                        </div>
                      </div>
                    </div>
                  )}
                </div>
              </AccordionContent>
            </AccordionItem>

            <AccordionItem value="validation-rules">
              <AccordionTrigger>Validation Rules</AccordionTrigger>
              <AccordionContent>
                <div className="space-y-4">
                  {Object.entries(validationRules[selectedType]).map(([field, rule]) => (
                    <div key={field} className="flex items-start space-x-2">
                      <Badge variant="outline" className="mt-1">
                        {field}
                      </Badge>
                      <span className="text-sm text-muted-foreground">{rule}</span>
                    </div>
                  ))}
                </div>
              </AccordionContent>
            </AccordionItem>
          </Accordion>

          <Alert>
            <Icons.info className="h-4 w-4" />
            <AlertTitle>Date Format</AlertTitle>
            <AlertDescription>
              Selected date format: {dateFormats.find(f => f.value === selectedDateFormat)?.label}
            </AlertDescription>
          </Alert>

          <Form {...form}>
            <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4">
              <FormField
                control={form.control}
                name="file"
                render={({ field: { value, onChange, ...field } }) => (
                  <FormItem>
                    <FormLabel>Files</FormLabel>
                    <FormControl>
                      <Input
                        type="file"
                        accept=".json,.csv,.xlsx"
                        multiple
                        onChange={e => {
                          const _files = e.target.files;
                          if (files) {
                            onChange(files);
                            handleFileChange(files[0]);
                          }
                        }}
                        {...field}
                      />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />
              <div className="text-sm text-muted-foreground">
                <p>Supported file formats:</p>
                <ul className="list-disc pl-4">
                  <li>JSON (.json)</li>
                  <li>CSV (.csv)</li>
                  <li>Excel (.xlsx)</li>
                </ul>
                <p className="mt-2">Supported data types:</p>
                <ul className="list-disc pl-4">
                  <li>Expenses</li>
                  <li>Income</li>
                  <li>Goals</li>
                  <li>Challenges</li>
                </ul>
              </div>
              {preview && (
                <div className="space-y-2">
                  <div className="flex items-center justify-between">
                    <h3 className="text-sm font-medium">Preview</h3>
                    <Badge variant="outline">{preview.type}</Badge>
                  </div>
                  <div className="rounded-md border">
                    <Table>
                      <TableHeader>
                        <TableRow>
                          {preview.headers.map(header => (
                            <TableHead key={header}>{header}</TableHead>
                          ))}
                        </TableRow>
                      </TableHeader>
                      <TableBody>
                        {preview.data.map((row, index) => (
                          <TableRow key={index}>
                            {preview.headers.map(header => (
                              <TableCell key={header}>{row[header]?.toString() || ''}</TableCell>
                            ))}
                          </TableRow>
                        ))}
                      </TableBody>
                    </Table>
                  </div>
                  {preview.errors && (
                    <div className="text-sm text-destructive">
                      {preview.errors.map((error, index) => (
                        <p key={index}>{error}</p>
                      ))}
                    </div>
                  )}
                </div>
              )}
              <div className="flex justify-end space-x-2">
                <Button type="button" variant="outline" onClick={() => setOpen(false)}>
                  Cancel
                </Button>
                <Button type="submit" disabled={isLoading || !preview}>
                  {isLoading && <Icons.spinner className="mr-2 h-4 w-4 animate-spin" />}
                  Import
                </Button>
              </div>
            </form>
          </Form>
        </div>
      </DialogContent>
    </Dialog>
  );
}

