    setIsRenamingBranch(true);
    try {
      await onRenameBranch(branchToRename, newBranchName.trim());
      setRenameDialogOpen(false);
      setBranchToRename(null);
      setNewBranchName('');
      setRenameError(null);

      toast({
        title: 'Branch renamed',
