                        <div className="text-sm font-medium">Conflict Patterns</div>
                      </div>
                      <div className="p-4">{renderConflictPatternsChart()}</div>
                    </div>

                    <div className="rounded-lg border">
                      <div className="border-b p-4">
                        <div className="text-sm font-medium">Contributor Activity</div>
                      </div>
                      <div className="p-4">{renderContributorActivityChart()}</div>
                    </div>
                  </div>

                  <div className="rounded-lg border">
                    <div className="border-b p-4">
                      <div className="text-sm font-medium">Success Rates by Strategy</div>
                    </div>
                    <div className="p-4">{renderSuccessRatesChart()}</div>
                  </div>
                </div>
              )}
            </div>
          )}
        </DialogContent>
      </Dialog>

      <Dialog open={comparisonDialogOpen} onOpenChange={setComparisonDialogOpen}>
        <DialogContent className="max-w-4xl">
          <DialogHeader>
            <DialogTitle>Contributor Comparison</DialogTitle>
            <DialogDescription>
              Compare performance and collaboration patterns between team members
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4">
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="text-sm font-medium">Contributor 1</label>
                <Select
                  value={selectedContributors?.[0] || ''}
                  onValueChange={value => {
                    setSelectedContributors(prev => [value, prev?.[1] || '']);
                    setContributorComparison(null);
                  }}
                >
                  <SelectTrigger>
                    <SelectValue placeholder="Select contributor" />
                  </SelectTrigger>
                  <SelectContent>
                    {mergeAnalytics?.teamCollaboration.contributorActivity.map(contributor => (
                      <SelectItem
                        key={contributor.contributor}
                        value={contributor.contributor}
                        disabled={contributor.contributor === selectedContributors?.[1]}
                      >
                        {contributor.contributor}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium">Contributor 2</label>
                <Select
                  value={selectedContributors?.[1] || ''}
                  onValueChange={value => {
                    setSelectedContributors(prev => [prev?.[0] || '', value]);
                    setContributorComparison(null);
                  }}
                >
                  <SelectTrigger>
                    <SelectValue placeholder="Select contributor" />
                  </SelectTrigger>
                  <SelectContent>
                    {mergeAnalytics?.teamCollaboration.contributorActivity.map(contributor => (
                      <SelectItem
                        key={contributor.contributor}
                        value={contributor.contributor}
                        disabled={contributor.contributor === selectedContributors?.[0]}
                      >
                        {contributor.contributor}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            </div>

            {selectedContributors?.[0] && selectedContributors?.[1] && (
              <Button
                className="w-full"
                onClick={handleCompareContributors}
                disabled={isComparingContributors}
              >
                {isComparingContributors ? (
                  <>
                    <Icons.spinner className="mr-2 h-4 w-4 animate-spin" />
                    Comparing...
                  </>
                ) : (
                  <>
                    <Icons.compare className="mr-2 h-4 w-4" />
                    Compare Contributors
                  </>
                )}
              </Button>
            )}

            {contributorComparison && (
              <div className="space-y-6">
                <div className="grid grid-cols-3 gap-4">
                  <div className="rounded-lg border p-4">
                    <div className="text-sm font-medium">Merge Success Rate</div>
                    <div className="mt-2 space-y-2">
                      <div className="flex items-center justify-between">
                        <span className="text-sm">{contributorComparison.contributor1}</span>
                        <span
                          className={getMetricColor(
                            contributorComparison.metrics.mergeSuccessRate.contributor1,
                            contributorComparison.metrics.mergeSuccessRate.contributor2
                          )}
                        >
                          {(
                            contributorComparison.metrics.mergeSuccessRate.contributor1 * 100
                          ).toFixed(1)}
                          %
                        </span>
                      </div>
                      <div className="flex items-center justify-between">
                        <span className="text-sm">{contributorComparison.contributor2}</span>
                        <span
                          className={getMetricColor(
                            contributorComparison.metrics.mergeSuccessRate.contributor2,
                            contributorComparison.metrics.mergeSuccessRate.contributor1
                          )}
                        >
                          {(
                            contributorComparison.metrics.mergeSuccessRate.contributor2 * 100
                          ).toFixed(1)}
                          %
                        </span>
                      </div>
                    </div>
                  </div>

                  <div className="rounded-lg border p-4">
                    <div className="text-sm font-medium">Avg. Resolution Time</div>
                    <div className="mt-2 space-y-2">
                      <div className="flex items-center justify-between">
                        <span className="text-sm">{contributorComparison.contributor1}</span>
                        <span
                          className={getMetricColor(
                            contributorComparison.metrics.averageResolutionTime.contributor2,
                            contributorComparison.metrics.averageResolutionTime.contributor1
                          )}
                        >
                          {(
                            contributorComparison.metrics.averageResolutionTime.contributor1 / 1000
                          ).toFixed(1)}
                          s
                        </span>
                      </div>
                      <div className="flex items-center justify-between">
                        <span className="text-sm">{contributorComparison.contributor2}</span>
                        <span
                          className={getMetricColor(
                            contributorComparison.metrics.averageResolutionTime.contributor1,
                            contributorComparison.metrics.averageResolutionTime.contributor2
                          )}
                        >
                          {(
                            contributorComparison.metrics.averageResolutionTime.contributor2 / 1000
                          ).toFixed(1)}
                          s
                        </span>
                      </div>
                    </div>
                  </div>

                  <div className="rounded-lg border p-4">
                    <div className="text-sm font-medium">Resolution Efficiency</div>
                    <div className="mt-2 space-y-2">
                      <div className="flex items-center justify-between">
                        <span className="text-sm">{contributorComparison.contributor1}</span>
                        <span
                          className={getMetricColor(
                            contributorComparison.metrics.conflictResolutionEfficiency.contributor1,
                            contributorComparison.metrics.conflictResolutionEfficiency.contributor2
                          )}
                        >
                          {(
                            contributorComparison.metrics.conflictResolutionEfficiency
                              .contributor1 * 100
                          ).toFixed(1)}
                          %
                        </span>
                      </div>
                      <div className="flex items-center justify-between">
                        <span className="text-sm">{contributorComparison.contributor2}</span>
                        <span
                          className={getMetricColor(
                            contributorComparison.metrics.conflictResolutionEfficiency.contributor2,
                            contributorComparison.metrics.conflictResolutionEfficiency.contributor1
                          )}
                        >
                          {(
                            contributorComparison.metrics.conflictResolutionEfficiency
                              .contributor2 * 100
                          ).toFixed(1)}
                          %
                        </span>
                      </div>
                    </div>
                  </div>
                </div>

                <div className="rounded-lg border">
                  <div className="border-b p-4">
                    <div className="text-sm font-medium">Common Conflict Patterns</div>
                  </div>
                  <ScrollArea className="h-[200px]">
                    <div className="space-y-4 p-4">
                      {contributorComparison.metrics.commonConflicts.map((conflict, index) => (
                        <div key={index} className="space-y-2">
                          <div className="flex items-center justify-between">
                            <div className="font-medium">{conflict.field}</div>
                            <Badge variant="outline">
                              {(conflict.frequency * 100).toFixed(0)}% frequency
                            </Badge>
                          </div>
                          <div className="text-sm text-muted-foreground">
                            Resolution pattern: {conflict.resolutionPattern}
                          </div>
                        </div>
                      ))}
                    </div>
                  </ScrollArea>
                </div>

                <div className="rounded-lg border">
                  <div className="border-b p-4">
                    <div className="text-sm font-medium">Collaboration History</div>
                  </div>
                  <ScrollArea className="h-[200px]">
                    <div className="space-y-4 p-4">
                      {contributorComparison.metrics.collaborationHistory.map((event, index) => (
                        <div key={index} className="space-y-2">
                          <div className="flex items-center justify-between">
                            <div className="font-medium">
                              {format(new Date(event.date), 'MMM d, yyyy')}
                            </div>
                            <Badge
                              variant="outline"
                              className={
                                event.type === 'merge'
                                  ? 'text-green-500'
                                  : event.type === 'conflict'
                                    ? 'text-yellow-500'
                                    : 'text-blue-500'
                              }
                            >
                              {event.type.charAt(0).toUpperCase() + event.type.slice(1)}
                            </Badge>
                          </div>
                          <div className="text-sm text-muted-foreground">{event.description}</div>
                        </div>
                      ))}
                    </div>
                  </ScrollArea>
                </div>
              </div>
            )}
          </div>
        </DialogContent>
      </Dialog>

      <Dialog open={strategyDialogOpen} onOpenChange={setStrategyDialogOpen}>
        <DialogContent className="max-w-4xl">
          <DialogHeader>
            <DialogTitle>Merge Strategy Recommendation</DialogTitle>
            <DialogDescription>
              AI-powered recommendations based on historical patterns and team performance
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4">
            <div className="flex items-center justify-between">
              <div className="space-y-1">
                <div className="text-sm font-medium">Source Branch</div>
                <div className="text-lg font-semibold">{selectedSourceBranch}</div>
              </div>
              <div className="space-y-1">
                <div className="text-sm font-medium">Target Branch</div>
                <div className="text-lg font-semibold">{selectedTargetBranch}</div>
              </div>
            </div>

            <Button
              className="w-full"
              onClick={handleGetMergeStrategy}
              disabled={isLoadingStrategy}
            >
              {isLoadingStrategy ? (
                <>
                  <Icons.spinner className="mr-2 h-4 w-4 animate-spin" />
                  Analyzing...
                </>
              ) : (
                <>
                  <Icons.lightbulb className="mr-2 h-4 w-4" />
                  Get Strategy Recommendation
                </>
              )}
            </Button>

            {mergeStrategy && (
              <div className="space-y-6">
                <div className="rounded-lg border p-4">
                  <div className="flex items-center justify-between">
                    <div className="space-y-1">
                      <div className="text-sm font-medium">Recommended Strategy</div>
                      <div
                        className={`text-lg font-semibold ${getStrategyColor(
                          mergeStrategy.strategy
                        )}`}
                      >
                        {mergeStrategy.strategy.charAt(0).toUpperCase() +
                          mergeStrategy.strategy.slice(1)}
                      </div>
                    </div>
                    <Badge variant="outline">
                      {(mergeStrategy.confidence * 100).toFixed(0)}% confidence
                    </Badge>
                  </div>
                </div>

                <div className="rounded-lg border">
                  <div className="border-b p-4">
                    <div className="text-sm font-medium">Reasoning</div>
                  </div>
                  <div className="space-y-2 p-4">
                    {mergeStrategy.reasoning.map((reason, index) => (
                      <div key={index} className="flex items-start space-x-2">
                        <Icons.checkCircle className="mt-1 h-4 w-4 text-green-500" />
                        <span className="text-sm">{reason}</span>
                      </div>
                    ))}
                  </div>
                </div>

                <div className="rounded-lg border">
                  <div className="border-b p-4">
                    <div className="text-sm font-medium">Suggested Approach</div>
                  </div>
                  <div className="space-y-4 p-4">
                    <div className="space-y-2">
                      {mergeStrategy.suggestedApproach.steps.map((step, index) => (
                        <div key={index} className="flex items-start space-x-2">
                          <div className="flex h-6 w-6 items-center justify-center rounded-full bg-primary/10 text-xs font-medium">
                            {index + 1}
                          </div>
                          <span className="text-sm">{step}</span>
                        </div>
                      ))}
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                      <div className="rounded-md border p-3">
                        <div className="text-sm font-medium">Estimated Time</div>
                        <div className="text-lg font-semibold">
                          {mergeStrategy.suggestedApproach.estimatedTime} minutes
                        </div>
                      </div>
                      <div className="rounded-md border p-3">
                        <div className="text-sm font-medium">Risk Level</div>
                        <Badge
                          variant="outline"
                          className={
                            mergeStrategy.suggestedApproach.riskLevel === 'high'
                              ? 'text-red-500'
                              : mergeStrategy.suggestedApproach.riskLevel === 'medium'
                                ? 'text-yellow-500'
                                : 'text-green-500'
                          }
                        >
                          {mergeStrategy.suggestedApproach.riskLevel.toUpperCase()}
                        </Badge>
                      </div>
                    </div>
                  </div>
                </div>

                <div className="rounded-lg border">
                  <div className="border-b p-4">
                    <div className="text-sm font-medium">Historical Success</div>
                  </div>
                  <div className="p-4">
                    <div className="space-y-4">
                      {mergeStrategy.historicalSuccess.map((history, index) => (
                        <div key={index} className="space-y-2">
                          <div className="flex items-center justify-between">
                            <div className="font-medium">{history.strategy}</div>
                            <Badge variant="outline">
                              {(history.successRate * 100).toFixed(0)}% success
                            </Badge>
                          </div>
                          <div className="text-sm text-muted-foreground">
                            Average time: {(history.averageTime / 1000).toFixed(1)}s
                          </div>
                          <div className="h-1 rounded-full bg-muted">
                            <div
                              className="h-full rounded-full bg-primary"
                              style={{
                                width: `${history.successRate * 100}%`,
                              }}
                            />
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                </div>
              </div>
            )}
          </div>
        </DialogContent>
      </Dialog>

      {renderTeamTrendsDialog()}
      {renderConflictPredictionDialog()}
      {renderChartFilterDialog()}
      {renderExportTemplateDialog()}
      {renderTeamAlertsDialog()}
      {renderCustomMetricsDialog()}
      {renderAnalyticsSection()}
    </div>
  );
}

export default TemplateVersionDiff;

import React from 'react';

const ExportDialog: React.FC<{ isOpen?: boolean; onClose?: () => void }> = ({
  isOpen,
  onClose,
}) => <div>Export Dialog Component (stub)</div>;

ExportDialog.displayName = 'ExportDialog';

export { ExportDialog };

import { useState, useMemo } from 'react';
import { Button, Badge, ScrollArea } from '@/components/ui';
import { Icons } from '@/components/ui/icons';
import { _format } from 'date-fns';
import { _TemplateVersion } from '@/lib/import';
import { _useToast } from '@/components/ui/use-toast';
import { _TemplateVersionDiffTypes } from './types';
import { VersionComparison } from './VersionComparison';
import { MergeAnalytics } from './MergeAnalytics';
import { BranchManagement } from './BranchManagement';
import { TeamAlerts } from './TeamAlerts';
import { ExportDialog } from './ExportDialog';

// Placeholder components for lazy-loaded components
const _VersionComparison = () => <div>Version Comparison Component</div>;
const _MergeAnalytics = () => <div>Merge Analytics Component</div>;
const _BranchManagement = () => <div>Branch Management Component</div>;
const _TeamAlerts = () => <div>Team Alerts Component</div>;

interface TemplateVersionDiffProps {
  versions: TemplateVersion[];
  onRestore: (version: number) => Promise<void>;
  isRestoring: boolean;
  onAddTag?: (version: number, tag: string) => Promise<void>;
  onRemoveTag?: (version: number, tag: string) => Promise<void>;
  onAddNote?: (version: number, note: string) => Promise<void>;
  onImport?: (template: any, versions: TemplateVersion[]) => Promise<void>;
  onBranch?: (version: number, branchName: string) => Promise<void>;
  onMerge?: (
    sourceVersion: number,
    targetVersion: number,
    resolutions?: Record<string, any>
  ) => Promise<void>;
  onDeleteBranch?: (branchName: string) => Promise<void>;
  onRenameBranch?: (oldName: string, newName: string) => Promise<void>;
  onArchiveBranch?: (branchName: string) => Promise<void>;
  onUnarchiveBranch?: (branchName: string) => Promise<void>;
  mergeHistory?: TemplateVersionDiffTypes.MergeHistory[];
  template: any;
  onCompareBranches?: (
    sourceBranch: string,
    targetBranch: string
  ) => Promise<TemplateVersionDiffTypes.BranchComparison>;
  onUpdateProtectionRule?: (rule: TemplateVersionDiffTypes.BranchProtectionRule) => Promise<void>;
  onDeleteProtectionRule?: (branchName: string) => Promise<void>;
  protectionRules?: TemplateVersionDiffTypes.BranchProtectionRule[];
  userRole?: string;
  onAddResolutionNote?: (mergeId: string, field: string, note: string) => Promise<void>;
  mergeAnalytics?: TemplateVersionDiffTypes.MergeAnalytics;
  onExportAnalytics?: (options: TemplateVersionDiffTypes.ExportOptions) => Promise<void>;
  onCompareContributors?: (
    contributor1: string,
    contributor2: string
  ) => Promise<TemplateVersionDiffTypes.ContributorComparison>;
  onGetMergeStrategyRecommendation?: (
    sourceBranch: string,
    targetBranch: string,
    contributors: string[]
  ) => Promise<TemplateVersionDiffTypes.MergeStrategyRecommendation>;
  chartData?: {
    mergeFrequency: TemplateVersionDiffTypes.TimeSeriesData[];
    conflictPatterns: TemplateVersionDiffTypes.ChartData[];
    contributorActivity: TemplateVersionDiffTypes.ChartData[];
    successRates: TemplateVersionDiffTypes.ChartData[];
  };
  onGetTeamPerformanceTrends?: (
    dateRange: TemplateVersionDiffTypes.DateRange
  ) => Promise<TemplateVersionDiffTypes.TeamPerformanceTrend[]>;
  onPredictConflicts?: (
    sourceBranch: string,
    targetBranch: string
  ) => Promise<TemplateVersionDiffTypes.ConflictPrediction>;
  onFilterCharts?: (filter: TemplateVersionDiffTypes.ChartFilter) => Promise<void>;
  onSaveExportTemplate?: (template: TemplateVersionDiffTypes.ExportTemplate) => Promise<void>;
  onLoadExportTemplate?: (templateId: string) => Promise<TemplateVersionDiffTypes.ExportTemplate>;
  onDeleteExportTemplate?: (templateId: string) => Promise<void>;
  exportTemplates?: TemplateVersionDiffTypes.ExportTemplate[];
  onCreateTeamAlert?: (
    alert: Omit<TemplateVersionDiffTypes.TeamAlert, 'id' | 'createdAt' | 'status'>
  ) => Promise<void>;
  onUpdateTeamAlert?: (
    alertId: string,
    status: TemplateVersionDiffTypes.TeamAlert['status']
  ) => Promise<void>;
  teamAlerts?: TemplateVersionDiffTypes.TeamAlert[];
  onCreateCustomMetric?: (
    metric: Omit<TemplateVersionDiffTypes.CustomMetric, 'id' | 'createdAt' | 'updatedAt'>
  ) => Promise<void>;
  onUpdateCustomMetric?: (
    metricId: string,
    metric: Partial<TemplateVersionDiffTypes.CustomMetric>
  ) => Promise<void>;
  onDeleteCustomMetric?: (metricId: string) => Promise<void>;
  customMetrics?: TemplateVersionDiffTypes.CustomMetric[];
  onGetMergeStrategyInsights?: () => Promise<TemplateVersionDiffTypes.MergeStrategyInsight[]>;
  onGetTeamPerformanceInsights?: () => Promise<TemplateVersionDiffTypes.TeamPerformanceInsight[]>;
  onCreateFormula?: (formula: Omit<TemplateVersionDiffTypes.FormulaBuilder, 'id'>) => Promise<void>;
  onUpdateFormula?: (
    formulaId: string,
    updates: Partial<TemplateVersionDiffTypes.FormulaBuilder>
  ) => Promise<void>;
  onDeleteFormula?: (formulaId: string) => Promise<void>;
  mergeStrategyInsights?: TemplateVersionDiffTypes.MergeStrategyInsight[];
  teamPerformanceInsights?: TemplateVersionDiffTypes.TeamPerformanceInsight[];
  formulaBuilders?: TemplateVersionDiffTypes.FormulaBuilder[];
}

export function TemplateVersionDiff({
  versions,
  onRestore,
  isRestoring,
  onAddTag,
  onRemoveTag,
  onAddNote,
  onImport,
  onBranch,
  onMerge,
  onDeleteBranch,
  onRenameBranch,
  onArchiveBranch,
  onUnarchiveBranch,
  mergeHistory = [],
  template,
  onCompareBranches,
  onUpdateProtectionRule,
  onDeleteProtectionRule,
  protectionRules = [],
  userRole,
  onAddResolutionNote,
  mergeAnalytics,
  onExportAnalytics,
  onCompareContributors,
  onGetMergeStrategyRecommendation,
  chartData,
  onGetTeamPerformanceTrends,
  onPredictConflicts,
  onFilterCharts,
  onSaveExportTemplate,
  onLoadExportTemplate,
  onDeleteExportTemplate,
  exportTemplates = [],
  onCreateTeamAlert,
  onUpdateTeamAlert,
  teamAlerts = [],
  onCreateCustomMetric,
  onUpdateCustomMetric,
  onDeleteCustomMetric,
  customMetrics = [],
  onGetMergeStrategyInsights,
  onGetTeamPerformanceInsights,
  onCreateFormula,
  onUpdateFormula,
  onDeleteFormula,
  mergeStrategyInsights = [],
  teamPerformanceInsights = [],
  formulaBuilders = [],
}: TemplateVersionDiffProps) {
  const [selectedVersion, setSelectedVersion] = useState<number | null>(null);
  const [compareVersion, setCompareVersion] = useState<number | null>(null);
  const [activeTab, setActiveTab] = useState<'versions' | 'analytics' | 'branches' | 'alerts'>(
    'versions'
  );
  const [isExportDialogOpen, setIsExportDialogOpen] = useState(false);
  const { toast } = useToast();

  const _sortedVersions = useMemo(() => {
    return [...versions].sort((a, b) => b.version - a.version);
  }, [versions]);

  const _handleVersionSelect = (version: number) => {
    setSelectedVersion(version);
  };

  const _handleCompare = () => {
    if (selectedVersion && compareVersion) {
      // Handle comparison logic
    }
  };

  const _handleRestore = async (_version: number) => {
    try {
      await onRestore(_version);
      toast({
        title: 'Version Restored',
        description: `Successfully restored to version ${_version}`,
      });
    } catch (error) {
      toast({
        title: 'Restore Failed',
        description: 'Failed to restore version',
        variant: 'destructive',
      });
    }
  };

  const _renderVersionsList = () => (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <h3 className="text-lg font-semibold">Template Versions</h3>
        <Button variant="outline" size="sm" onClick={() => setIsExportDialogOpen(true)}>
          <Icons.download className="mr-2 h-4 w-4" />
          Export
        </Button>
      </div>

      <ScrollArea className="h-96">
        <div className="space-y-2">
          {_sortedVersions.map(version => (
            <div
              key={version.version}
              className={`cursor-pointer rounded-lg border p-4 transition-colors ${
                selectedVersion === version.version
                  ? 'border-primary bg-primary/5'
                  : 'border-border hover:border-primary/50'
              }`}
              onClick={() => _handleVersionSelect(version.version)}
            >
              <div className="flex items-start justify-between">
                <div>
                  <div className="flex items-center gap-2">
                    <span className="font-medium">Version {version.version}</span>
                    {version.tags?.map(tag => (
                      <Badge key={tag} variant="secondary" className="text-xs">
                        {tag}
                      </Badge>
                    ))}
                  </div>
                  <p className="mt-1 text-sm text-muted-foreground">
                    {_format(new Date(version.createdAt), 'PPP')}
                  </p>
                  {version.notes && (
                    <p className="mt-2 text-sm text-muted-foreground">{version.notes}</p>
                  )}
                </div>
                <div className="flex gap-2">
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={e => {
                      e.stopPropagation();
                      _handleRestore(version.version);
                    }}
                    disabled={isRestoring}
                  >
                    {isRestoring ? (
                      <Icons.spinner className="h-4 w-4 animate-spin" />
                    ) : (
                      <Icons.rotateCcw className="h-4 w-4" />
                    )}
                  </Button>
                </div>
              </div>
            </div>
          ))}
        </div>
      </ScrollArea>
    </div>
  );

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold">Template Version Management</h2>
          <p className="text-muted-foreground">Manage and compare template versions</p>
        </div>
        <div className="flex gap-2">
          <Button variant="outline" onClick={() => setActiveTab('versions')}>
            Versions
          </Button>
          <Button variant="outline" onClick={() => setActiveTab('analytics')}>
            Analytics
          </Button>
          <Button variant="outline" onClick={() => setActiveTab('branches')}>
            Branches
          </Button>
          <Button variant="outline" onClick={() => setActiveTab('alerts')}>
            Alerts
          </Button>
        </div>
      </div>

      {/* Content */}
      <div className="rounded-lg border p-6">
        {activeTab === 'versions' && (
          <VersionComparison
            selectedVersion={selectedVersion}
            compareVersion={compareVersion}
            onCompareVersionChange={setCompareVersion}
            onCompare={_handleCompare}
            versions={versions}
          />
        )}

        {activeTab === 'analytics' && (
          <MergeAnalytics
            mergeAnalytics={mergeAnalytics}
            chartData={chartData}
            onExportAnalytics={onExportAnalytics}
            onCompareContributors={onCompareContributors}
            onGetMergeStrategyRecommendation={onGetMergeStrategyRecommendation}
            onGetTeamPerformanceTrends={onGetTeamPerformanceTrends}
