  const [userBehavior, setUserBehavior] = useState<UserBehavior | null>(null);
  const [loading, setLoading] = useState(false);
  const [showAdvanced, setShowAdvanced] = useState(false);

  const _loadBehavioralData = useCallback(async () => {
    if (!session?.user?.email) return;
    try {
      const _response = await fetch('/api/smart-saving/behavioral');
      if (response.ok) {
        const _data = await response.json();
        setRules(data.rules || defaultRules);
      }
    } catch (error) {
      console.error('Error loading behavioral data:', error);
    }
  }, [session?.user?.email]);

  const _loadUserBehavior = useCallback(async () => {
    if (!session?.user?.email) return;
    try {
      const _response = await fetch('/api/user/behavior');
      if (response.ok) {
        const _data = await response.json();
        setUserBehavior(data);
      }
    } catch (error) {
      console.error('Error loading user behavior:', error);
    }
  }, [session?.user?.email]);

  useEffect(() => {
    loadBehavioralData();
    loadUserBehavior();
  }, [loadBehavioralData, loadUserBehavior]);

  const _toggleRule = async (ruleId: string) => {
    setLoading(true);
    try {
      const _updatedRules = rules.map(rule =>
        rule.id === ruleId ? { ...rule, enabled: !rule.enabled } : rule
      );

      const _response = await fetch('/api/smart-saving/behavioral', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ rules: updatedRules }),
      });

      if (response.ok) {
        setRules(updatedRules);
        const _rule = rules.find(r => r.id === ruleId);
        toast.success(`${rule?.enabled ? 'Disabled' : 'Enabled'} ${rule?.name}`);
      }
    } catch (error) {
      console.error('Error toggling rule:', error);
      toast.error('Failed to update rule');
    } finally {
      setLoading(false);
    }
  };

  const _updateIntensity = async (ruleId: string, intensity: number) => {
    const _updatedRules = rules.map(rule => (rule.id === ruleId ? { ...rule, intensity } : rule));
    setRules(updatedRules);

    // Debounce the API call
    setTimeout(async () => {
      try {
        await fetch('/api/smart-saving/behavioral', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
