              <div key={mission.id} className="space-y-3 rounded-lg border p-4">
                <div className="flex items-start justify-between">
                  <div className="flex items-center gap-2">
                    <_IconComponent className="h-4 w-4" />
                    <div>
                      <h4 className="font-medium">{mission.title}</h4>
                      <p className="text-sm text-muted-foreground">{mission.description}</p>
                    </div>
                  </div>
                  <Badge className={getDifficultyColor(mission.difficulty)}>
                    {mission.difficulty}
                  </Badge>
                </div>

                <div className="space-y-2">
                  <div className="flex justify-between text-sm">
                    <span>Progress</span>
                    <span>
                      {mission.progress}/{mission.target}
                    </span>
                  </div>
                  <Progress value={_progressPercentage} className="h-2" />
                </div>

                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-2">
                    <div className={`h-3 w-3 rounded-full ${getCategoryColor(mission.category)}`} />
                    <span className="text-xs capitalize text-muted-foreground">
                      {mission.category}
                    </span>
                  </div>

                  <div className="flex items-center gap-2">
                    <span className="text-xs text-muted-foreground">
                      Reward: {mission.reward.value}
                    </span>
                    {_progressPercentage >= 100 && (
                      <Button
                        size="sm"
                        onClick={() => _completeMission(mission.id)}
                        disabled={loading}
                      >
                        Complete
                      </Button>
                    )}
                  </div>
                </div>

                {mission.streak && (
                  <div className="flex items-center gap-1 text-xs text-orange-600">
                    <Icons.flame className="h-3 w-3" />
                    <span>{mission.streak} day streak</span>
                  </div>
                )}
              </div>
            );
          })}
        </div>

        {/* Completed Missions Toggle */}
        {completedMissions.length > 0 && (
          <div className="space-y-4">
            <Button
              variant="ghost"
              onClick={() => setShowCompleted(!showCompleted)}
              className="w-full"
            >
              {showCompleted ? 'Hide' : 'Show'} Completed Missions ({completedMissions.length})
            </Button>

            {showCompleted && (
              <div className="space-y-2">
                {completedMissions.map(mission => (
                  <div key={mission.id} className="rounded-lg border bg-muted/50 p-3">
                    <div className="flex items-center justify-between">
                      <div>
                        <h4 className="font-medium line-through">{mission.title}</h4>
                        <p className="text-xs text-muted-foreground">{mission.description}</p>
                      </div>
                      <Badge variant="outline" className="text-green-600">
                        Completed
                      </Badge>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}

        {/* Personalized Recommendations */}
        {userProfile && (
          <div className="rounded-lg bg-blue-50 p-4 dark:bg-blue-950">
            <h4 className="mb-2 font-medium">💡 Personalized for You</h4>
            <p className="text-sm text-muted-foreground">
              Based on your {userProfile.incomeType} income pattern as a {userProfile.profession},
              we've tailored these missions to help you build better financial habits.
            </p>
          </div>
        )}

        {/* Mission Stats */}
        <div className="grid grid-cols-3 gap-4 text-center">
          <div>
            <div className="text-2xl font-bold text-green-600">{completedMissions.length}</div>
            <div className="text-xs text-muted-foreground">Completed</div>
          </div>
          <div>
            <div className="text-2xl font-bold text-blue-600">{activeMissions.length}</div>
            <div className="text-xs text-muted-foreground">Active</div>
          </div>
          <div>
            <div className="text-2xl font-bold text-purple-600">
              {missions.reduce((sum, m) => sum + (m.streak || 0), 0)}
            </div>
            <div className="text-xs text-muted-foreground">Total Streaks</div>
          </div>
        </div>

        <span>Don&apos;t stop now!</span>
      </CardContent>
    </Card>
  );
}

import * as React from 'react';
import { Check, ChevronsUpDown } from 'lucide-react';

import { _cn } from '@/lib/utils';
import { Button } from '@/components/ui';
import {
  Command,
  CommandEmpty,
  CommandGroup,
  CommandInput,
  CommandItem,
} from '@/components/ui/command';
import { Popover, PopoverContent, PopoverTrigger } from '@/components/ui/popover';

export interface ComboboxOption {
  value: string;
  label: string;
}

interface ComboboxProps {
  options: ComboboxOption[];
  value?: string;
  onValueChange?: (value: string) => void;
  placeholder?: string;
  emptyText?: string;
  className?: string;
}

export function Combobox({
  options,
  value,
  onValueChange,
  placeholder = 'Select option...',
  emptyText = 'No results found.',
  className,
}: ComboboxProps) {
  const [open, setOpen] = React.useState(false);

  return (
    <Popover open={open} onOpenChange={setOpen}>
      <PopoverTrigger asChild>
        <Button
          variant="outline"
          role="combobox"
          aria-expanded={open}
          className={cn('w-full justify-between', className)}
        >
          {value ? options.find(option => option.value === value)?.label : placeholder}
          <ChevronsUpDown className="ml-2 h-4 w-4 shrink-0 opacity-50" />
        </Button>
      </PopoverTrigger>
      <PopoverContent className="w-full p-0">
        <Command>
          <CommandInput placeholder={placeholder} />
          <CommandEmpty>{emptyText}</CommandEmpty>
          <CommandGroup>
            {options.map(option => (
              <CommandItem
                key={option.value}
                value={option.value}
                onSelect={currentValue => {
                  onValueChange?.(currentValue === value ? '' : currentValue);
                  setOpen(false);
                }}
              >
                <Check
                  className={cn(
                    'mr-2 h-4 w-4',
                    value === option.value ? 'opacity-100' : 'opacity-0'
                  )}
                />
                {option.label}
              </CommandItem>
            ))}
          </CommandGroup>
        </Command>
      </PopoverContent>
    </Popover>
  );
}

Combobox.displayName = 'Combobox';
export { Combobox };

