            setRules(prev =>
              prev.map(rule => (rule.id === payload.new.id ? (payload.new as SavingsRule) : rule))
            );
          } else if (payload.eventType === 'DELETE') {
            setRules(prev => prev.filter(rule => rule.id !== payload.old.id));
          }
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [session?.user?.email]);

