// Get next API key with rotation
function getNextApiKey(service: 'dribbble'): string | null {
  const _keys = API_KEYS[service];
  if (!keys.length) return null;

  const _currentIndex = API_KEYS.currentIndex[service];
  API_KEYS.currentIndex[service] = (currentIndex + 1) % keys.length;
  return keys[currentIndex];
}

