import Redis from 'ioredis';
import { _LRUCache } from 'lru-cache';

// Redis client for distributed caching
const _redis = new Redis(process.env.REDIS_URL || 'redis://localhost:6379');

// In-memory LRU cache for local caching
const _lruCache = new LRUCache({
  max: 500, // Maximum number of items
  ttl: 1000 * 60 * 5, // 5 minutes TTL
});

// Cache keys
const _CACHE_KEYS = {
  DASHBOARD: (userId: string) => `dashboard:${userId}`,
  CALENDAR: (userId: string) => `calendar:${userId}`,
  QUOTE: (quoteId: string) => `quote:${quoteId}`,
  AI_CONTEXT: (userId: string) => `ai:context:${userId}`,
} as const;

// Cache options
const _CACHE_OPTIONS = {
  DASHBOARD: { ttl: 60 }, // 1 minute
  CALENDAR: { ttl: 300 }, // 5 minutes
  QUOTE: { ttl: 3600 }, // 1 hour
  AI_CONTEXT: { ttl: 1800 }, // 30 minutes
} as const;

// Cache interface
interface CacheOptions {
  ttl: number;
  useLocalCache?: boolean;
}

// Cache service
export class CacheService {
  // Get data from cache
  static async get<T>(key: string, options: CacheOptions): Promise<T | null> {
    // Try local cache first if enabled
    if (options.useLocalCache) {
      const _localData = lruCache.get(key);
      if (localData) return localData as T;
    }

    // Try Redis cache
    const _data = await redis.get(key);
    if (!data) return null;

    const _parsedData = JSON.parse(data);

    // Update local cache if enabled
    if (options.useLocalCache) {
      lruCache.set(key, parsedData);
    }

    return parsedData as T;
  }

  // Set data in cache
  static async set(key: string, data: any, options: CacheOptions): Promise<void> {
    const _serializedData = JSON.stringify(data);

    // Set in Redis
    await redis.set(key, serializedData, 'EX', options.ttl);

    // Set in local cache if enabled
    if (options.useLocalCache) {
      lruCache.set(key, data);
    }
  }

  // Delete data from cache
  static async delete(key: string): Promise<void> {
    await redis.del(key);
    lruCache.delete(key);
  }

  // Clear all cache
  static async clear(): Promise<void> {
    await redis.flushall();
    lruCache.clear();
  }

  // Get dashboard data with caching
  static async getDashboardData(userId: string): Promise<any> {
    const _cacheKey = CACHE_KEYS.DASHBOARD(userId);
    const _cachedData = await this.get(cacheKey, CACHE_OPTIONS.DASHBOARD);

    if (cachedData) {
      return cachedData;
    }

    // Fetch fresh data
    const _data = await fetchDashboardData(userId);
    await this.set(cacheKey, data, CACHE_OPTIONS.DASHBOARD);
    return data;
  }

  // Get calendar data with caching
  static async getCalendarData(userId: string): Promise<any> {
    const _cacheKey = CACHE_KEYS.CALENDAR(userId);
    const _cachedData = await this.get(cacheKey, CACHE_OPTIONS.CALENDAR);

    if (cachedData) {
      return cachedData;
    }

    // Fetch fresh data
    const _data = await fetchCalendarData(userId);
    await this.set(cacheKey, data, CACHE_OPTIONS.CALENDAR);
    return data;
  }

  // Get quote data with caching
  static async getQuoteData(quoteId: string): Promise<any> {
    const _cacheKey = CACHE_KEYS.QUOTE(quoteId);
    const _cachedData = await this.get(cacheKey, CACHE_OPTIONS.QUOTE);

    if (cachedData) {
      return cachedData;
    }

    // Fetch fresh data
    const _data = await fetchQuoteData(quoteId);
    await this.set(cacheKey, data, CACHE_OPTIONS.QUOTE);
    return data;
  }

  // Get AI context with caching
  static async getAIContext(userId: string): Promise<any> {
    const _cacheKey = CACHE_KEYS.AI_CONTEXT(userId);
    const _cachedData = await this.get(cacheKey, CACHE_OPTIONS.AI_CONTEXT);

    if (cachedData) {
      return cachedData;
    }

    // Fetch fresh data
    const _data = await fetchAIContext(userId);
    await this.set(cacheKey, data, CACHE_OPTIONS.AI_CONTEXT);
    return data;
  }
}

