export async function importData(userId: string, data: ImportData) {
  try {
    // Validate the imported data
    const _validatedData = importSchema.parse(data);

    // Import data in a transaction
    await prisma.$transaction(async tx => {
      // Import expenses
      if (validatedData.expenses?.length) {
        await tx.expense.createMany({
          data: validatedData.expenses.map(expense => ({
            ...expense,
            userId,
          })),
        });
      }

      // Import income
      if (validatedData.income?.length) {
        await tx.income.createMany({
          data: validatedData.income.map(income => ({
            ...income,
            userId,
          })),
        });
      }

      // Import goals
      if (validatedData.goals?.length) {
        await tx.goal.createMany({
          data: validatedData.goals.map(goal => ({
            ...goal,
            userId,
          })),
        });
      }

      // Import challenges
      if (validatedData.challenges?.length) {
        await tx.challenge.createMany({
          data: validatedData.challenges.map(challenge => ({
            ...challenge,
            userId,
          })),
        });
      }
    });

    return {
      success: true,
      message: 'Data imported successfully',
      summary: {
        expenses: validatedData.expenses?.length || 0,
        income: validatedData.income?.length || 0,
        goals: validatedData.goals?.length || 0,
        challenges: validatedData.challenges?.length || 0,
      },
    };
  } catch (error) {
    if (error instanceof z.ZodError) {
      return {
        success: false,
        message: 'Invalid data format',
        errors: error.errors.map(err => ({
          path: err.path.join('.'),
          message: err.message,
        })),
      };
    }
    throw error;
  }
}

export function validateImportFile(file: File): Promise<ImportData> {
  return new Promise((resolve, reject) => {
    const _reader = new FileReader();

    reader.onload = event => {
      try {
        const _data = JSON.parse(event.target?.result as string);
        resolve(data);
      } catch (error) {
        reject(new Error('Invalid JSON file'));
      }
    };

    reader.onerror = () => {
      reject(new Error('Failed to read file'));
    };

    reader.readAsText(file);
  });
}

export async function parseFileToImportData(
  file: File,
  options: {
    dateFormat?: string;
    fieldMapping?: Record<string, string>;
    dataType?: keyof typeof fieldMappings;
  } = {}
): Promise<ImportData> {
  const { dateFormat = 'yyyy-MM-dd', fieldMapping, dataType } = options;
  const _schemas = createValidationSchemas(dateFormat);
  const data: ImportData = {};

  const _mapFields = (row: any, type: keyof typeof fieldMappings) => {
    const _mapping = fieldMapping || {};
    const _possibleFields = fieldMappings[type];
    const mappedRow: any = {};

    Object.entries(possibleFields).forEach(([targetField, _possibleValues]) => {
      const _sourceField = mapping[targetField] || targetField;
      const _value = row[sourceField];

      if (value !== undefined) {
        // Handle date fields
        if (targetField.includes('date') || targetField === 'deadline') {
          mappedRow[targetField] = value;
        }
        // Handle numeric fields
        else if (
          targetField === 'amount' ||
          targetField === 'target' ||
          targetField === 'current'
        ) {
          mappedRow[targetField] = parseFloat(value);
        }
        // Handle string fields
        else {
          mappedRow[targetField] = value;
        }
      }
    });

    return mappedRow;
  };

  if (file.type === 'application/json') {
    return validateImportFile(file);
  } else if (file.type === 'text/csv') {
    const _result = await new Promise<Papa.ParseResult<any>>((resolve, _reject) => {
      Papa.parse(file, {
        header: true,
        complete: resolve,
        error: _reject,
      });
    });

    if (dataType) {
      const _mappedData = result.data.map(row => mapFields(row, dataType));
      data[dataType] = mappedData;
    } else {
      // Auto-detect data type based on headers
      const _headers = result.meta.fields || [];
      if (
        headers.some(h => fieldMappings.expenses.amount.includes(h)) &&
        headers.some(h => fieldMappings.expenses.category.includes(h))
      ) {
        data.expenses = result.data.map(row => mapFields(row, 'expenses'));
      } else if (
        headers.some(h => fieldMappings.income.amount.includes(h)) &&
        headers.some(h => fieldMappings.income.source.includes(h))
      ) {
        data.income = result.data.map(row => mapFields(row, 'income'));
      }
    }
  } else if (file.type === 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet') {
    const _buffer = await file.arrayBuffer();
    const _workbook = XLSX.read(buffer);
    const _firstSheet = workbook.Sheets[workbook.SheetNames[0]];
    const _jsonData = XLSX.utils.sheet_to_json(firstSheet);

    if (dataType) {
      const _mappedData = jsonData.map((row: any) => mapFields(row, dataType));
      data[dataType] = mappedData;
    } else {
      // Auto-detect data type based on headers
      const _headers = Object.keys(jsonData[0] || {});
      if (
        headers.some(h => fieldMappings.expenses.amount.includes(h)) &&
        headers.some(h => fieldMappings.expenses.category.includes(h))
      ) {
        data.expenses = jsonData.map((row: any) => mapFields(row, 'expenses'));
      } else if (
        headers.some(h => fieldMappings.income.amount.includes(h)) &&
        headers.some(h => fieldMappings.income.source.includes(h))
      ) {
        data.income = jsonData.map((row: any) => mapFields(row, 'income'));
      }
    }
  }

  return data;
}

// Bulk import result type
export type BulkImportResult = {
  success: boolean;
  files: {
    name: string;
    success: boolean;
    message?: string;
    summary?: {
      expenses: number;
      income: number;
      goals: number;
      challenges: number;
    };
  }[];
  total: {
    expenses: number;
    income: number;
    goals: number;
    challenges: number;
  };
};

export async function bulkImport(
  userId: string,
  files: File[],
  options: TransformOptions = {}
): Promise<BulkImportResult> {
  const result: BulkImportResult = {
    success: true,
    files: [],
    total: {
      expenses: 0,
      income: 0,
      goals: 0,
      challenges: 0,
    },
  };

  for (const file of files) {
    try {
      const _importData = await parseFileToImportData(file, {
        dateFormat: options.dateFormat,
        dataType: undefined, // Auto-detect type
      });

      // Transform the data
      if (importData.expenses) {
        importData.expenses = importData.expenses.map(row =>
          transformRow(row, 'expenses', options)
        );
      }
      if (importData.income) {
        importData.income = importData.income.map(row => transformRow(row, 'income', options));
      }
      if (importData.goals) {
        importData.goals = importData.goals.map(row => transformRow(row, 'goals', options));
      }
      if (importData.challenges) {
        importData.challenges = importData.challenges.map(row =>
          transformRow(row, 'challenges', options)
        );
      }

      // Import the data
      const _importResult = await importData(userId, importData);

      result.files.push({
        name: file.name,
        success: importResult.success,
        message: importResult.message,
        summary: importResult.summary,
      });

      if (importResult.summary) {
        result.total.expenses += importResult.summary.expenses;
        result.total.income += importResult.summary.income;
        result.total.goals += importResult.summary.goals;
        result.total.challenges += importResult.summary.challenges;
      }
    } catch (error) {
      result.files.push({
        name: file.name,
        success: false,
        message: error instanceof Error ? error.message : 'Import failed',
      });
      result.success = false;
    }
  }

  return result;
}

// Template version type
export type TemplateVersion = {
  id: string;
  templateId: string;
  version: number;
  changes: {
    field: string;
    oldValue: any;
    newValue: any;
  }[];
  createdBy: string;
  createdAt: Date;
};

// Update SavedTemplate type to include version info
export type SavedTemplate = {
  id: string;
  name: string;
  type: keyof typeof templateData;
  format: 'json' | 'csv' | 'xlsx';
  options: TemplateOptions;
  category?: string;
  tags: string[];
  isPublic: boolean;
  sharedWith: string[];
  createdBy: string;
  createdAt: Date;
  updatedAt: Date;
  currentVersion: number;
  versions: TemplateVersion[];
};

// Save template with versioning
export async function saveTemplate(
  userId: string,
  name: string,
  type: keyof typeof templateData,
  format: 'json' | 'csv' | 'xlsx',
  options: TemplateOptions,
  category?: string,
  tags: string[] = [],
  isPublic = false,
  sharedWith: string[] = []
): Promise<SavedTemplate> {
  return prisma.$transaction(async tx => {
    const _template = await tx.template.create({
      data: {
        name,
        type,
        format,
        options: options as any,
        category,
        tags,
        isPublic,
        sharedWith,
        createdBy: userId,
        currentVersion: 1,
      },
    });

    // Create initial version
    await tx.templateVersion.create({
      data: {
        templateId: template.id,
        version: 1,
        changes: [],
        createdBy: userId,
      },
    });

    return {
      ...template,
      versions: [],
    };
  });
}

// Update template with versioning
export async function updateTemplate(
  templateId: string,
  updates: Partial<
    Omit<SavedTemplate, 'id' | 'createdBy' | 'createdAt' | 'currentVersion' | 'versions'>
  >,
  userId: string
): Promise<SavedTemplate> {
  return prisma.$transaction(async tx => {
    const _template = await tx.template.findUnique({
      where: { id: templateId },
      include: { versions: true },
    });

    if (!template) {
      throw new Error('Template not found');
    }

    // Track changes
    const changes: TemplateVersion['changes'] = [];
    Object.entries(updates).forEach(([field, newValue]) => {
      const _oldValue = template[field as keyof typeof template];
      if (JSON.stringify(oldValue) !== JSON.stringify(newValue)) {
        changes.push({
          field,
          oldValue,
          newValue,
        });
      }
    });

    if (changes.length === 0) {
      return template;
    }

    // Create new version
    const _newVersion = await tx.templateVersion.create({
      data: {
        templateId,
        version: template.currentVersion + 1,
        changes,
        createdBy: userId,
      },
    });

    // Update template
    const _updatedTemplate = await tx.template.update({
      where: { id: templateId },
      data: {
        ...updates,
        currentVersion: newVersion.version,
      },
      include: { versions: true },
    });

    return updatedTemplate;
  });
}

// Get template version history
export async function getTemplateVersions(templateId: string): Promise<TemplateVersion[]> {
  return prisma.templateVersion.findMany({
    where: { templateId },
    orderBy: { version: 'desc' },
  });
}

// Restore template to a specific version
export async function restoreTemplateVersion(
  templateId: string,
  version: number,
  userId: string
): Promise<SavedTemplate> {
  return prisma.$transaction(async tx => {
    const _template = await tx.template.findUnique({
      where: { id: templateId },
      include: { versions: true },
    });

    if (!template) {
      throw new Error('Template not found');
    }

    const _targetVersion = template.versions.find(v => v.version === version);
    if (!targetVersion) {
      throw new Error('Version not found');
    }

    // Apply all changes up to the target version
    const updates: any = {};
    template.versions
      .filter(v => v.version <= version)
      .forEach(v => {
        v.changes.forEach(change => {
          updates[change.field] = change.newValue;
        });
      });

    // Create new version for the restore
    const _newVersion = await tx.templateVersion.create({
      data: {
        templateId,
        version: template.currentVersion + 1,
        changes: [
          {
            field: 'version_restore',
            oldValue: template.currentVersion,
            newValue: version,
          },
        ],
        createdBy: userId,
      },
    });

    // Update template
    const _updatedTemplate = await tx.template.update({
      where: { id: templateId },
      data: {
        ...updates,
        currentVersion: newVersion.version,
      },
      include: { versions: true },
    });

    return updatedTemplate;
  });
}

