}

export interface BudgetSaverConfig {
  enabled: boolean;
  categories: { name: string; cap: number }[];
  goalId?: string;
}

export interface TriggerSaveConfig {
  enabled: boolean;
  triggers: { keyword: string; amount: number }[];
  goalId?: string;
}

export interface IncomeSplitConfig {
