export interface TrialStatus {
  isActive: boolean;
  daysRemaining: number;
  trialExpiresAt: Date | null;
  trialStartedAt: Date | null;
  isExpired: boolean;
}

/**
 * Get trial status for a user
 */
export async function getTrialStatus(userId: string): Promise<TrialStatus> {
  const _user = await prisma.user.findUnique({
    where: { id: userId },
    select: {
      trialStartedAt: true,
      trialExpiresAt: true,
      isTrialActive: true,
      subscriptionLevel: true,
    },
  });

  if (!_user) {
    throw new Error('User not found');
  }

  // If user has a paid subscription, trial is not relevant
  if (_user.subscriptionLevel !== 'FREE') {
    return {
      isActive: false,
      daysRemaining: 0,
      trialExpiresAt: _user.trialExpiresAt,
      trialStartedAt: _user.trialStartedAt,
      isExpired: false,
    };
  }

  const _now = new Date();
  const _trialExpiresAt = _user.trialExpiresAt;
  const _isExpired = _trialExpiresAt ? _now > _trialExpiresAt : false;
  const _isActive = _user.isTrialActive && !_isExpired;

  let _daysRemaining = 0;
  if (_trialExpiresAt && !_isExpired) {
    const _diffTime = _trialExpiresAt.getTime() - _now.getTime();
    _daysRemaining = Math.ceil(_diffTime / (1000 * 60 * 60 * 24));
  }

  return {
    isActive: _isActive,
    daysRemaining: _daysRemaining,
    trialExpiresAt: _trialExpiresAt,
    trialStartedAt: _user.trialStartedAt,
    isExpired: _isExpired,
  };
}

/**
 * Check if user has access to features based on trial/subscription status
 */
export async function hasFeatureAccess(userId: string, feature: string): Promise<boolean> {
  const _user = await prisma.user.findUnique({
    where: { id: userId },
    select: {
      subscriptionLevel: true,
      isTrialActive: true,
      trialExpiresAt: true,
    },
  });

  if (!_user) {
    return false;
  }

  // If user has a paid subscription, they have access
  if (_user.subscriptionLevel !== 'FREE') {
    return true;
  }

  // For free users, check if trial is active
  if (_user.isTrialActive && _user.trialExpiresAt && new Date() < _user.trialExpiresAt) {
    return true;
  }

  // Trial expired or not active
  return false;
}

/**
 * Update trial status (called by cron job or webhook)
 */
export async function updateTrialStatus(userId: string): Promise<void> {
  const _user = await prisma.user.findUnique({
    where: { id: userId },
    select: {
      trialExpiresAt: true,
      isTrialActive: true,
    },
  });

  if (!_user) {
    return;
  }

  const _now = new Date();
  const _isExpired = _user.trialExpiresAt ? _now > _user.trialExpiresAt : false;

  if (_isExpired && _user.isTrialActive) {
    await prisma.user.update({
      where: { id: userId },
      data: { isTrialActive: false },
    });
  }
}

/**
 * Get users with expired trials
 */
export async function getExpiredTrials(): Promise<string[]> {
  const _now = new Date();

  const _expiredUsers = await prisma.user.findMany({
    where: {
      subscriptionLevel: 'FREE',
      trialExpiresAt: {
        lt: _now,
      },
      isTrialActive: true,
    },
    select: {
      id: true,
    },
  });

  return _expiredUsers.map(user => user.id);
}

/**
