export async function middleware(request: NextRequest) {
  try {
    // Get the pathname of the request
    const path = request.nextUrl.pathname;

    // Early return for static files and public assets - no processing needed
    if (
      path.startsWith('/_next/') ||
      path.startsWith('/api/') ||
      path.includes('.') || // Skip files with extensions (images, css, js, etc.)
      path === '/favicon.ico' ||
      path.startsWith('/static/') ||
      path.startsWith('/images/')
    ) {
      return NextResponse.next();
    }

    // Define public paths that don't require authentication
    const isPublicPath = path === '/login' || path === '/register' || path === '/forgot-password';

    // Early return for public paths - no auth check needed
    if (isPublicPath) {
      return NextResponse.next();
    }

    // Get the token only for protected routes
    const token = await getToken({
      req: request,
      secret: process.env.NEXTAUTH_SECRET,
    });

    // Add debugging logs only in development
    if (process.env.NODE_ENV === 'development') {
      console.log(
        `[Middleware] Path: ${path}, Public: ${isPublicPath}, Token: ${token ? 'Present' : 'Missing'}`
      );
    }

    // Redirect logic
    if (!token) {
      // If user is not logged in and tries to access protected path, redirect to login
      if (process.env.NODE_ENV === 'development') {
        console.log(`[Middleware] Redirecting unauthenticated user from ${path} to /login`);
      }
      return NextResponse.redirect(new URL('/login', request.url));
    }

    // Add error handling headers
    const response = NextResponse.next();
    response.headers.set('x-middleware-cache', 'no-cache');
    response.headers.set('x-middleware-skip', 'false');

    // Check trial/PRO access for protected routes
    const trialResponse = await checkTrialAccess(request, token);
    if (trialResponse) return trialResponse;

    return response;
  } catch (error) {
    console.error('Middleware error:', error);

    // Return a proper error response
    return new NextResponse(
      JSON.stringify({
        error: 'Internal Server Error',
        message: 'An unexpected error occurred',
      }),
      {
        status: 500,
        headers: {
          'Content-Type': 'application/json',
        },
      }
    );
  }
}

