// Features that require active trial or paid subscription
const _PROTECTED_FEATURES = [
  '/dashboard',
  '/expenses',
  '/income',
  '/goals',
  '/challenges',
  '/analytics',
  '/reports',
  '/settings',
  '/api/expenses',
  '/api/income',
  '/api/goals',
  '/api/challenges',
];

// Features that are always accessible (even with expired trial)
const _PUBLIC_FEATURES = [
  '/pricing',
  '/trial/upgrade',
  '/api/trial/status',
  '/api/trial/upgrade',
  '/logout',
  '/api/auth',
];

// This middleware now only checks cookies/JWTs for trial status
export function checkTrialAccess(request: NextRequest) {
  const { pathname } = request.nextUrl;

  // Log cookies and path for debugging
  const _trialStatus = request.cookies.get('trial-status')?.value;
  const _userRole = request.cookies.get('user-role')?.value;
  console.log(
    '[MIDDLEWARE] Path:',
    pathname,
    'trial-status:',
    _trialStatus,
    'user-role:',
    _userRole
  );

  // Allow public features
  if (_PUBLIC_FEATURES.some(feature => pathname.startsWith(feature))) {
    return null;
  }

  // Check if this is a protected feature
  const _isProtectedFeature = _PROTECTED_FEATURES.some(feature => pathname.startsWith(feature));

  if (!_isProtectedFeature) {
    return null;
  }

  // If trial-status or user-role cookies are missing, redirect to login
  if (!_trialStatus || !_userRole) {
    return NextResponse.redirect(new URL('/login', request.url));
  }

  // Allow access for PRO or SUPER_ADMIN users (if role is set in cookie)
  if (_userRole === 'PRO' || _userRole === 'SUPER_ADMIN') {
    return null;
  }

  // Allow access if trial is active
  if (_trialStatus === 'active' || _trialStatus === 'pro') {
    return null;
  }

  // If trial is expired, redirect to upgrade page
  if (_trialStatus === 'expired') {
    return NextResponse.redirect(new URL('/trial/expired', request.url));
  }

  // If trial status is missing, allow access (or optionally block)
  // TODO: You may want to handle this differently depending on your auth flow
  return null;
}

